INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('dd73725b-3bd1-49a5-8af2-6df72524428b', 'MT.3.UM.UT.1', 'State and write dates in a variety of ways.', 'mathematics', '3', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
