  ('1706dafe-d34e-4181-b49c-8128911f0bff', 'MT.3.UM.UT.6', 'Create and solve problems involving time', 'mathematics', '3', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', NULL, '3-4', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('361bc580-0f70-44be-8fc3-bbe3df45afeb', 'MT.3.NS.NP.1', 'Count by 2''s, 5''s, 10''s, 20''s, 25''s, and 100''s.', 'mathematics', '3', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1b4adc28-3f50-4fd0-9a2d-23845f727bbb', 'MT.3.NS.NP.2', 'Identify the ordinal position of an object in an arranged set, and identify an object in a given position in such a set.', 'mathematics', '3', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('edeed511-f7cd-4d61-827b-4345ce88d5d5', 'MT.3.NS.NP.3', 'Define and use number-associated vocabulary (e.g., pair, dozen, double, triple, half of, etc.)', 'mathematics', '3', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('18dd9560-09ae-4285-8f28-502d3dc0bca9', 'MT.3.NS.NP.4', 'Identify the pattern in a sequence of numbers, complete and extend sequences of numbers.', 'mathematics', '3', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c964ce43-b53b-4d92-bdf0-16a9b2f3e641', 'MT.3.NS.OS.1', 'Recall the basic facts for addition and subtraction.', 'mathematics', '3', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('755fa918-8406-4202-b0d0-9dccb877e691', 'MT.3.NS.OS.2', 'Use the calculator to perform the four basic operations; and explain the steps followed to input the data and the results obtained', 'mathematics', '3', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
