  ('e665bd0c-ee9b-4aad-8550-5897055a450a', 'MT.3.NS.OS.4', 'Create and solve problems involving whole number addition and subtraction problems without and with regrouping with results not exceeding 999.', 'mathematics', '3', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
