  ('a8f203d0-a75f-4834-b91e-1687fcd6d62a', 'MT.3.NS.OS.7', 'Use repeated addition and subtraction to multiply and divide a two-digit number by a one-digit number, without and with remainders.', 'mathematics', '3', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('3ea2737e-a673-47be-abc9-01dc3c999b2e', 'MT.3.NS.OS.8', 'Create and solve problems which involve addition of two proper fractions with like denominators.', 'mathematics', '3', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
