  ('da505065-ad66-48da-8d30-7c3f8aca1c80', 'MT.3.NS.PR.4', 'Speak of, represent and model proper fractions as a sum of several smaller fractions', 'mathematics', '3', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('fc7bd5c1-cd7b-4209-b969-3260b7176910', 'MT.3.NS.PR.5', 'Speak of, and create models to demonstrate knowledge of equivalence between two proper fractions', 'mathematics', '3', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '3-4', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('80bba605-ffdc-495c-b232-0de64c92d44d', 'MT.3.NS.PR.6', 'Compare unit fractions, and proper fractions with like denominators, using vocabulary (such as ''greater than'' and ''less than'')', 'mathematics', '3', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '3-4', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('10e6bd2a-c79f-4a83-9794-ff351fce8f56', 'MT.3.NS.PR.7', 'Continue to create to speak of, and create models to show part-whole relationship', 'mathematics', '3', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '3-4', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b878dc01-39fb-4a77-8a49-2a4aeee21766', 'MT.3.NS.UN.1', 'Read, write and represent numbers up to ninety nine (999) in a variety of ways (in words, in numbers, in place value charts, using counting blocks/rods; drawings/pictures)', 'mathematics', '3', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('54dafbb7-c63b-465e-b2bc-814995bbd218', 'MT.3.NS.UN.2', 'Use knowledge of face value, place value and total value to write, model and compare numbers with up to three digits.', 'mathematics', '3', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
