  ('6dfaca89-dca8-4dcd-b85f-4e5a5dd58732', 'MT.3.NS.UN.5', 'Round off two-digit and three-digit numbers to the nearest ten and/or hundred.', 'mathematics', '3', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
