  ('f53c8b79-fc85-42e5-8687-f9a8ce868b8a', 'MT.3.NS.UN.7', 'Develop fluency when working with whole numbers', 'mathematics', '3', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('80d3c410-3a38-4ac3-8cfd-359b2458b306', 'MT.4.DH.DC.1', 'Ask questions suitable for collecting relevant data; and accurately record responses.', 'mathematics', '4', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('03c657cd-f113-44df-8012-48068df65eff', 'MT.4.DH.DC.2', 'Collect data through simple observations, interviews and questionnaires.', 'mathematics', '4', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
