  ('24650d35-e8cd-4f86-b0b4-c776c5ff1831', 'MT.4.DH.DI.1', 'Read, in different directions, information presented in tables, picture graphs and bar graphs (left to right; right to left; top to bottom; bottom to top).', 'mathematics', '4', 'Data Handling', 'DH', 'Data Interpretation', 'DI', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
