  ('a0a6b10b-d890-4b55-984e-0178860b539e', 'MT.4.DH.DI.3', 'Interpret data presented in pupil-constructed tables, picture graphs and bar graphs; and tables and graphs found in familiar sources such as students'' textbooks, newspaper, internet.', 'mathematics', '4', 'Data Handling', 'DH', 'Data Interpretation', 'DI', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
