  ('7ddb270a-9bc9-4fef-b982-4f5328f0c59e', 'LA.K.LS.SI.11', 'Interpret the facial expressions and gestures of a speaker', 'language-arts', 'K', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1a4c2275-c2ad-45f6-a90e-3f8a449a3526', 'MT.4.DH.DR.2', 'Construct picture graphs and bar graphs on grid paper using one-to-one correspondence; and appropriately labelling axes and giving graphs a title that matches the data display.', 'mathematics', '4', 'Data Handling', 'DH', 'Data Representation', 'DR', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
