  ('05985519-0c2f-4546-b21e-504f4b875ee7', 'MT.4.GT.DS.3', 'Use knowledge of geometry to give simple directions; and complete drawing of a simple 2D shapes (triangles, squares and rectangles); and two shapes of same size in different positions on grid paper.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('cf475101-bda4-4ba2-932f-5035014f59c5', 'MT.4.GT.DS.4', 'Use a variety of strategies to solve problems relating to position and direction.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('09c3a88e-5379-43a2-9112-fbd2d68fbdbf', 'MT.4.GT.PL.1', 'Distinguish among points, line segments, rays and lines; sketch representation of each in different orientations.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Points and Lines', 'PL', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('322577db-65a0-454b-9623-a01f29700dba', 'MT.4.GT.PL.2', 'Compare and contrast line segments, rays and lines in terms of end and start points; direction; and length.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Points and Lines', 'PL', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b1bb31aa-1bae-4ca3-9bcc-d1edb1b99781', 'MT.4.GT.PS.1', 'Sketch triangles of various sizes and shape in different orientations; and describe all triangles as having three sides and three angles.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('a6c8777a-7979-4f84-81b9-7644905e6182', 'MT.4.GT.PS.2', 'Speak of rectangles as having: four sides, two pairs of opposite sides that are equal, and four right angles', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('913a7d79-1278-46f2-aa83-305a0774f232', 'MT.4.GT.PS.3', 'Speak of squares as having: four equal sides, two pairs of opposite sides being equal; four right angles', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
