  ('f9432cb0-9afb-43de-a4e4-5d4569328372', 'MT.4.GT.PS.5', 'Work in small groups to draw circles; insert and label the parts (center, diameter, radius and circumference) of a circle; measure and compare radii and diameters; and use information gathered to formulate generalisations between radius and diameter.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '3-4', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0b977de1-051f-40f7-b05f-41ae60ff223d', 'MT.4.GT.PS.6', 'Describe, extend and generate simple geometric patterns involving plane shapes; and use a variety of strategies to solve problems related to 2-D shapes.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '3-4', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c2686f1d-8208-49a3-aab8-bc3a174c04dc', 'MT.4.GT.SS.1', 'Draw solid shapes using pencil and paper and basic computer software.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('71aafac5-66dd-4dcb-9075-85add7abd9be', 'MT.4.GT.SS.2', 'Describe (cubes, cuboids, cylinders, cones, spheres) in terms of the number of vertices, the number and shape of faces; draw/sketch nets of cubes, cuboids, cylinders, cones and sphere.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d48eca75-1a40-4f38-a8e4-a1baab434726', 'MT.4.GT.SS.3', 'Use a variety of strategies to explore and respond to problems based on 3D shapes and their nets.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ba85e7c6-a5aa-4822-8289-4c32a345afd5', 'MT.4.GT.UA.1', 'Illustrate the concept of an angle as being the amount of turns about a fixed point; and that angles are measured in degrees (°).', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f2ff0f3e-880e-4634-ab44-d578f634486c', 'MT.4.GT.UA.2', 'Demonstrate, and sketch a 90° angle (right angle) as a quarter (1/4) turn using tools such as grid paper, geoboard or simple computer programme; and compare the size of angles less than, equal to and greater than a quarter turn.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('fe5d0564-2abd-42b8-97d8-ccbec6d3f948', 'MT.4.GT.UA.3', 'Use a variety of strategies (drawing, trial and error; looking for patterns; practical work) to respond to problems involving angles.', 'mathematics', '4', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d06918f8-25b3-4118-be35-c25fe9c07b6a', 'MT.4.NS.NP.1', 'Describe, complete and extend given whole number patterns obtained from counting forwards or backwards, doubling, adding or subtracting a constant.', 'mathematics', '4', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f7f964f1-1d4d-40b0-a363-588d3c2d0ef7', 'MT.4.NS.NP.2', 'By analyzing the results obtained from computing with whole numbers, formulate and use the generalization (such as the order in which any two numbers are added does not change the result; a number multiplied by one gives the number itself; a number added to zero gives the number)', 'mathematics', '4', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1fb16417-ee67-4759-bb81-7667bde90bd7', 'MT.4.NS.NP.3', 'Use knowledge of number facts and generated rules to aid in calculations (e.g. 4 × 1 = 4; 4 × 10 = 10 × 4; and 5 – 0 = 5).', 'mathematics', '4', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('854ddd06-303d-4f4b-bdc8-5a61c03ad27b', 'MT.4.NS.OS.1', 'Use a variety of mental and written strategies to estimate and perform addition and subtraction with numbers up to 3 digits without and with regrouping', 'mathematics', '4', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9125da7b-a5d6-4349-b457-999adb5c9c94', 'MT.4.NS.OS.2', 'Use a variety of mental and written strategies to estimate then multiply up to 9 × 9 and divide up to 81 ÷ 9; multiply and divide whole numbers by 10, 100, using calculator to check for pattern; and use identified patterns to formulate generalizations.', 'mathematics', '4', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('16c9e39e-9411-4011-bae5-14ca3b615cf4', 'MT.4.NS.OS.3', 'Use a variety of tools and strategies to estimate, multiply and divide 2-digit whole numbers by one-digit whole numbers, and reflecting on the effectiveness approaches used.', 'mathematics', '4', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('de07c2d5-5ebb-4ff9-931e-1a523e61f905', 'MT.4.NS.OS.4', 'Create and solve a variety of one and two steps problems involving addition, subtraction and multiplication; and develop the skill of checking the reasonableness of worked solution against initial estimated result.', 'mathematics', '4', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b66a4cac-7394-4091-abdb-8d6cb9967c92', 'MT.4.NS.OS.5', 'Use concrete and pictorial models to represent and compare sets of two fractions to find equivalence among halves, quarters and eighths; and between thirds and sixths; and to add fractions with the same denominator; and simplify fractions as necessary.', 'mathematics', '4', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0072102f-42eb-4604-b631-2eaaa35a44a2', 'MT.4.NS.OS.6', 'Count forwards and backwards in multiples of 6, 10, 25, 50 and 100, starting with a multiple of the number in which the counting is done', 'mathematics', '4', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('856122a2-a9f0-42ef-849a-687f6f7b8fc3', 'MT.4.NS.OS.7', 'Count forwards in fractional parts by halves, thirds, quarters, fifths and tenths beyond one whole; and count forward in decimal by tenths using numbers expressed to one decimal place', 'mathematics', '4', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '3-4', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('db5acf84-1d9e-4099-8272-f0923d842841', 'MT.4.NS.PR.1', 'Use terms such as twice as many, three time as much, to describe one quantity in terms of another quantity', 'mathematics', '4', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('11551930-7c34-420c-8ff0-b7a3911dd615', 'MT.4.NS.PR.2', 'Use simple examples to illustrate the relationship between addition and subtraction, and use knowledge of this relationship to check the correctness of addition and subtraction results.', 'mathematics', '4', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('72224f73-e824-4e92-b91a-c41e0b19cfb3', 'MT.4.NS.PR.3', 'Use a variety of tools and strategies to demonstrate an understanding of the relationship between the fraction and decimal representation of tenths.', 'mathematics', '4', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('dd79206a-56c0-401e-b224-04954ba883df', 'MT.4.NS.PR.4', 'Use knowledge of multiplication to demonstrate understanding of unit rates, and use such knowledge to solve simple problems', 'mathematics', '4', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('552af5ba-fd2d-480b-838d-b2dac0c2bae7', 'MT.4.NS.PR.5', 'Investigate relationships between whole numbers (e.g. sum of two odd numbers, sum of two even numbers)', 'mathematics', '4', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '3-4', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c8c388f2-0311-4aaa-8448-7f76cdcf6e79', 'MT.4.NS.PR.6', 'Continue to investigate multiple ways of creating models to show part-whole relationship of numbers', 'mathematics', '4', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '3-4', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4324c1a0-ceb9-45f0-8fdd-105243475abf', 'MT.4.NS.UN.1', 'Read, write, count, order, expand, and compare numbers up to 10,000, using a variety of tools; and differentiate between place value and total value of each digit; and round numbers up to 999 to nearest ten and hundred', 'mathematics', '4', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7ba4506b-91f1-4939-8ad7-6a2e5e2e0032', 'MT.4.NS.UN.2', 'Model, represent, compare and order fractions with denominator (2, 3, 4, 5, 6, 8 and 10); and use appropriate vocabulary to communicate correct ideas about fractions.', 'mathematics', '4', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d8522a70-1939-4e87-9215-1b41f90d8458', 'MT.4.NS.UN.3', 'Model, generate, and classify different groupings of numbers (odd, even, factors, multiples, proper fraction, improper fraction and mixed numbers) and explain the common features among the numbers in each group.', 'mathematics', '4', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4c1c168c-bd74-4e24-a635-3666ab8b44dc', 'MT.4.NS.UN.4', 'Create and solve problems involving ordinal numbers up to the one hundredth (100th) position', 'mathematics', '4', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('3a9c3bb3-ec7c-41ab-bbbe-b83997bfeb82', 'MT.4.NS.UN.5', 'Develop fluency when working with whole numbers', 'mathematics', '4', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('2b44202f-c592-4106-8c73-43e23a03963a', 'MT.4.NS.UN.6', 'Use a variety of tools and strategies (such as the number line, place value chart) to represent, compare and order decimal numbers represented to tenths', 'mathematics', '4', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f6c28b1f-619e-4280-846c-fba37e685393', 'MT.4.NS.UN.7', 'Use a variety of models (area model, number line model, and volume model) to represent, compare and order unit fractions with different but related denominators and other proper fractions with like denominators.', 'mathematics', '4', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '3-4', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7ca6908b-0f0b-4243-afdc-2536aa9fdfd0', 'MT.4.UM.LM.1', 'Select and use appropriate instruments and units (centimetre, metre and kilometre) to estimate, measure and record length and distance, giving reasons for choice; and convert from metre to centimetre and from kilometer to metre', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('12a84e56-3e7e-44c6-becc-06b1adc65424', 'MT.4.UM.LM.2', 'Work in small groups to estimate, measure and record distance around plane shapes using variety of tools (grid paper, geoboard and ruler) and use the term total distance around plane shape to mean perimeter', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0e04eab8-f2a3-451a-bdb0-6e1d9734259c', 'MT.4.UM.LM.3', 'Solve a variety of problems relating to length, distance and perimeter using different strategies', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('efeba8fd-ed32-4bea-a962-0193997806b9', 'MT.4.UM.MA.1', 'Estimate, measure and record surface enclosed by plane shapes by counting unit squares and using a variety of tools (centimetre grid, geoboard); and explaining strategies used.', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Materials', 'MA', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c87cf8c6-87f3-418e-8e12-58b64099a533', 'MT.4.UM.MA.2', 'Solve a variety of one and two step problems relating to the area of surfaces using different strategies', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Materials', 'MA', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4bd8d66a-3631-4559-9478-326b4684762f', 'MT.4.UM.MC.1', 'Estimate, measure and record capacity of containers in litre and millilitre using appropriate instrument.', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('161895a0-2d3d-41a9-9601-19ca7dcc0b8d', 'MT.4.UM.MC.2', 'Work in small groups to compare several examples of the same capacity given in millilitre and litre, and deduce that 1,000 millilitres = 1 litre; and use this knowledge to generate other equivalent measures between millilitre and litre (whole and half litre measures)', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('bf92f91f-1152-4b6d-a363-c0fb93d4f4ed', 'MT.4.UM.MC.3', 'Solve a variety of problems relating to capacity using different strategies', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('354a37a1-8e22-41cf-a6c3-3258cec8eb31', 'MT.4.UM.MM.1', 'Estimate, measure and record the mass of objects in gram and kilogram and using comparative vocabulary such as "same as"; "heavier than"; "lighter than" one kilogram.', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5aac0770-c86e-46bd-be07-9c0645bb981d', 'MT.4.UM.MM.2', 'Work in small groups to compare several examples of the mass of the same object given in gram and kilogram and conclude that 1,000 grams = 1 kilogram; and generate other equivalence between grams and kilograms (whole and half kilogram measures)', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('957ae308-3537-4213-af8f-6b8754ad361b', 'MT.4.UM.MM.3', 'Solve a variety of problems relating to mass using different strategies', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('41e17e4a-e479-4c32-9924-e6ee86013a9d', 'MT.4.UM.MW.1', 'Read and write amounts of money up $1,000 dollars and show an understanding of value of a large amounts of money ($100 to $1,000) by stating purchasing power of given amounts.', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d25f92a4-c3fe-46e6-b350-6af1f49b3bb1', 'MT.4.UM.MW.2', 'Use a variety of strategies, including concrete materials to add and subtract money involving dollars and cents not exceeding $100 (cents being multiples of 5 and 10); and generate different combinations of notes that give the same amount of money up to $100.', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1cf6bd5d-bb86-475e-92e5-1c489d099818', 'MT.4.UM.MW.3', 'Read, write and interpret prices of items; and use a variety of strategies to calculate the total cost (not exceeding $100) of a set of items, and make change from amounts up to $100', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9a3c19cd-7649-46f5-bb5f-d6da391ceb8a', 'MT.4.UM.MW.4', 'Use several strategies to create and solve problems involving money transactions.', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8774d03b-181b-47fe-9a4b-943ff80cf3db', 'MT.4.UM.UT.1', 'Explain the coordinated movement of the hour and minute hands of the clock, and use such knowledge to read, tell and record time in different intervals (hour, half hour, quarter hour, five minute) on both the analogue and digital clocks, using correct vocabulary and notation.', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('a9bf7720-617c-49bd-be07-9c3c3746c893', 'MT.4.UM.UT.2', 'Work in small groups, and using the skill of reading and interpreting data presented in tables deduce correct information from simple calendars, timetables and schedules', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5c2f859c-83f8-48f7-a267-953dca9266c1', 'MT.4.UM.UT.3', 'Use a variety of strategies to solve one and two steps problems relating to time; and reflect on the effectiveness of strategies used.', 'mathematics', '4', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8b23e1da-746f-4c0d-a9a7-6bf7bf00fadd', 'MT.5.DH.DC.1', 'Ask questions suitable for collecting relevant data; and accurately record responses.', 'mathematics', '5', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7dbc8b70-99ed-49e6-b74c-4cb27cb47871', 'MT.5.DH.DC.2', 'Collect data from interviews, observations, questionnaires, direct measures and simple experiments.', 'mathematics', '5', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('84361f5d-c6c2-4d79-bd04-78dbfc7294f3', 'MT.5.DH.DC.3', 'Continue to use tally charts and simple tables to count and record occurrences and construct organized collected data.', 'mathematics', '5', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d6041b8b-e027-4fff-ac23-7ae967ec0ce3', 'MT.5.DH.DI.1', 'Read and interpret data presented in different forms (tables, picture graphs, bar graphs and line graphs.', 'mathematics', '5', 'Data Handling', 'DH', 'Data Interpretation', 'DI', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5116d140-f4cf-496f-8661-61a531bbce0e', 'MT.5.DH.DI.2', 'Ask and answer questions based on information presented in tables, bar graphs, pictographs, and line graphs.', 'mathematics', '5', 'Data Handling', 'DH', 'Data Interpretation', 'DI', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('cf0c5b6a-9c26-43bd-991a-d3a7573081d2', 'MT.5.DH.DI.3', 'Work in small, using various strategies to determine the range, mode, median and mean of a set of a small set of data.', 'mathematics', '5', 'Data Handling', 'DH', 'Data Interpretation', 'DI', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('66c17772-2a0c-4dc1-a25b-fb50be39bbf0', 'MT.5.DH.DR.1', 'Continue to use simple tables to display collected data; and label columns and rows of tables accurately and give table a suitable title.', 'mathematics', '5', 'Data Handling', 'DH', 'Data Representation', 'DR', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f9470f09-2a50-40ac-ba5e-3afd30e1f702', 'MT.5.DH.DR.2', 'Construct pictographs and bar graphs on grid paper using simple scales (one to one; one to two; one to five); and appropriately label axes and giving graphs a title that matches the data display.', 'mathematics', '5', 'Data Handling', 'DH', 'Data Representation', 'DR', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a186c74a-ae11-4f5a-9626-283c06fad0bc', 'MT.5.DH.DR.3', 'Represent the same data in a variety of ways (table, pictograph and bar graph) and comment on the effectiveness of each method.', 'mathematics', '5', 'Data Handling', 'DH', 'Data Representation', 'DR', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9c3c3f4c-8a3f-42d2-9c43-091447c1999d', 'MT.5.GT.DS.1', 'Draw and label the axes of the first quadrant using a scale of 1cm to 1 unit; and use such information to identify, describe and represent the position of points and 2-D shapes within the first quadrant of the Cartesian Plane.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ff84429f-6ea1-4293-9818-c8854048c941', 'MT.5.GT.DS.2', 'Work in small group to construct 2D shapes; and identify, describe and represent translation in the first quadrant of the Cartesian Plane, using grid paper and computer programs.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('46a55ec7-e542-4663-b9dc-2d511cf77638', 'MT.5.GT.DS.3', 'Use a variety of strategies to solve problems relating to position and direction.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('bea7a033-1ac3-4f03-8fac-133ab0e43c16', 'MT.5.GT.PL.1', 'Use drawings to explain the concept of dimension as used in geometry to describe shapes.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Points and Lines', 'PL', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('fd8cad25-3440-4232-9233-31429823812e', 'MT.5.GT.PL.2', 'Explain why a point is zero dimensional but line segments, rays and lines are one dimensional.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Points and Lines', 'PL', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('76338b7e-3a35-4b43-ab32-0356b74f3b5c', 'MT.5.GT.PL.3', 'Use examples to illustrate and distinguish between parallel and intersecting lines; and vertical and horizontal lines.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Points and Lines', 'PL', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('eed71e09-9cc1-4454-889b-0d086eb6604c', 'MT.5.GT.PS.1', 'Continue to classify 2-D shapes in terms of their angular and linear properties and explain reasons on which classification was done; and continue to use terms (such as opposite sides, parallel sides, opposite angles) to describe properties of plane shapes.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('904285ca-3613-4b57-99ac-619a0723a6fb', 'MT.5.GT.PS.2', 'Describe a polygon as a closed figure bounded by straight sides; name and sketch polygons with up to six sides.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('2e44fd1e-d567-408b-9e5f-f0341d4a7f4e', 'MT.5.GT.PS.3', 'Classify quadrilaterals as (squares, rectangles, parallelograms, trapeziums, kites); and explain the common properties of the shapes in each group.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1a106abd-1187-4420-bb28-abffbfdbd6fe', 'MT.5.GT.PS.4', 'Classify triangles based on the property of: (1) number of equal sides (three equal sides, two equal sides, no equal sides) and (2) having or not having a right angle and explain the common features of the triangles in each group.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('93f49ba2-691a-4f88-9051-33a395997b4f', 'MT.5.GT.PS.5', 'Describe the diameter of a circle in terms of the radius and the radius in terms of the diameter.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('96889192-5cf4-41dd-a108-da2e4aa1a6cb', 'MT.5.GT.PS.6', 'Describe, extend and generate simple geometric patterns involving plane shapes; and use a variety of strategies to solve problems related to 2-D shapes.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('dd453944-1bd2-448c-8a81-1442d08801e2', 'MT.5.GT.SS.1', 'Use mathematics language such as (curved surface, flat faces, square face, rectangular face, circular face, curved edges) to accurately to describe properties of 3-D shapes.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c46b60a7-9d7c-40ec-9a50-73ec601b30d4', 'MT.5.GT.SS.2', 'Work in small groups to discuss, sketch and illustrate predictions of nets of given cubes and cuboids; and compare the actual nets of the shape with stated predictions.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('90859da2-10c2-4536-bcf2-e1fc19fe3dca', 'MT.5.GT.SS.3', 'Use a table to note differences in terms of properties between cubes and cuboids and cones and cylinders.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('55bc7842-1494-4cb7-b2b9-fd94f752a1c6', 'MT.5.GT.SS.4', 'Use a variety of strategies to explore and solve problems based on 3D shapes and their nets.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('033b83cf-867a-4d88-bed4-38814a1a5296', 'MT.5.GT.UA.1', 'Use the terms acute angle, right angle, obtuse angle, straight angle and reflex angle in relation to quarter turn, and half turn, whole turn', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('51ee6753-6384-47f7-86a5-422351d0bef2', 'MT.5.GT.UA.2', 'Recognize that two quarter turns equal half turn and reason that if a quarter turn equals 90° then two quarter turns equal half turn which is 180° and associate this reasoning with the concept of a straight angle measuring 180°.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1c7a4c1d-ee16-418e-8d17-f5a8c204e066', 'MT.5.GT.UA.3', 'Begin to use a simple one scale protractor with readings given in multiples of 5 degrees to draw and measure angles to the nearest ten degrees (10°).', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('3bf299bd-2c09-4e94-a57b-0498a5a8d6f6', 'MT.5.GT.UA.4', 'Apply knowledge of the angular properties of triangles, squares and rectangles to estimate and calculate missing angles.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('656f4aab-73f7-4a48-b49b-bb231fb59e08', 'MT.5.GT.UA.5', 'Use a variety of strategies (drawing, trial and error; looking for patterns; practical work) to respond to problems involving angles.', 'mathematics', '5', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a620ce89-d802-4eb5-ba43-5109f06832c5', 'MT.5.NS.NP.1', 'Complete, extend and describe (in words) given whole number patterns obtained from counting forward or backward, doubling or halving and adding, subtracting or multiplying by a constant.', 'mathematics', '5', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8355a139-da3f-4cc4-800d-4b5661bae740', 'MT.5.NS.NP.2', 'Generate a table of values to summarise results obtained from a pattern resulting from adding, subtracting or multiplying whole numbers by a constant to get successive terms.', 'mathematics', '5', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1a2db933-5026-462c-89dc-2a6a8de3a92e', 'MT.5.NS.NP.3', 'By analysing the results obtained from computing with whole numbers, formulate and use the generalizations (such as multiplication must be done before addition and subtraction; the order in which any two numbers are added or multiplied does not change the result).', 'mathematics', '5', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7157ea53-57f8-447c-bbb9-bbafe18db8eb', 'MT.5.NS.OS.1', 'Use a variety of mental strategies to add, subtract and multiply whole numbers (e.g. 15 × 6 may be thought of as 15 × 3 × 2).', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e632c640-8e7a-469b-a567-d4f6ab8fbdd4', 'MT.5.NS.OS.2', 'Use a variety of mental and written strategies to estimate and perform addition and subtraction of whole numbers up to 4-digit without and with regrouping.', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('42e852f7-ec7b-4b40-a0f5-f7e177231491', 'MT.5.NS.OS.3', 'Multiply and divide whole numbers by 10, 100, 1,000, use calculator to check for pattern, and use identified patterns to formulate generalizations.', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e9a73712-1120-471f-9dee-195dc463dfda', 'MT.5.NS.OS.4', 'Use a variety of strategies to multiply two two-digit whole numbers and multiple and divide three and two-digit whole numbers by one-digit whole numbers.', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('23c6b0a2-4803-4d4f-9414-73ca8a5a01ef', 'MT.5.NS.OS.5', 'Use simple examples to illustrate the relationship between addition and subtraction, and use knowledge of this relationship to check correctness of addition and subtraction results.', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5aeded3c-f115-4829-bd45-0c9d41399ea2', 'MT.5.NS.OS.6', 'Create and solve a variety of one and two step problems involving addition, subtraction, multiplication and division and develop the skill of checking the reasonableness of worked solution against initial estimated result.', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e93a1541-806f-4b05-85cc-ab49c0e070d3', 'MT.5.NS.OS.7', 'Use a variety of tools and strategies including the calculator to add and subtract decimal numbers to hundredths including money.', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('70e54f41-58cb-49d0-8264-11636b7c8a28', 'MT.5.NS.OS.8', 'Use concrete and pictorial models to represent, compare and generate sets of two and three equivalence fractions with denominators that are multiples of the smallest denominator.', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('06064b84-c536-456e-8cbe-d8ce5fa5b568', 'MT.5.NS.OS.9', 'Use a variety of tools and strategies to add and subtract two fractions (proper and improper mixed numbers) where one denominator is a multiple of the other; calculate a unit fraction of a whole (denominator not exceeding 12).', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('cc57d407-1434-4e0a-b8c6-4a6150341984', 'MT.5.NS.OS.10', 'Count forwards in 10''s and 100''s from any whole number; and count forward in decimal by tenths and hundredths using numbers expressed to one decimal place; and link to concept of measures', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b3cc4d09-2ccf-43e8-ab14-7afca0617077', 'LA.K.LS.SI.12', 'Listen attentively and courteously (body language, eye contact)', 'language-arts', 'K', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 12, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ad2b9a55-4bd4-4a4e-9548-cd93be70095f', 'MT.5.NS.OS.11', 'Count forwards in fractional parts by (halves, thirds, quarters, fifths, sixths, eights and tenths) beyond one whole.', 'mathematics', '5', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e960c2fb-1d3a-4889-afa0-b5eb0f9d4534', 'MT.5.NS.PR.1', 'Use terms, (such as half, quarter, twice) to describe the multiplicative relationship between two quantities', 'mathematics', '5', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c2258d23-ec99-4c7d-8602-fec909689f42', 'MT.5.NS.PR.2', 'Use equivalent fractions as a strategy to add and subtract fractions.', 'mathematics', '5', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('50593db3-97fa-404c-9b83-265b6746ff46', 'MT.5.NS.PR.3', 'Use a variety of tools and strategies to demonstrate an understanding of the relationship among a proper fraction, an improper fractions and a mixed numbers with related denominators', 'mathematics', '5', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('4ea6531a-4d01-4fb1-9b7c-a85ae58438d7', 'MT.5.NS.PR.4', 'Illustrate the concept of percent as the number of parts per hundred and make connection between percent and fraction using 100 as the denominator.', 'mathematics', '5', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('331f34a4-1797-4776-86c8-3075f838220d', 'MT.5.NS.PR.5', 'Work in small groups to investigate the relationship between the three ratios (fraction: decimal: percent); and use knowledge of this relationship to convert between fraction, decimal and percent (for halves, quarters, tenths and 100th).', 'mathematics', '5', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9ebb986c-8dd9-4345-aa43-1c4fb0748f36', 'MT.5.NS.UN.1', 'Read, write, count, order, expand, and compare numbers up to 100,000, using a variety of tools and models; and differentiate among face value, place value and total value of each digit', 'mathematics', '5', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('54ed04f9-34f1-4d88-8bcb-688798ca9436', 'MT.5.NS.UN.2', 'Round numbers to nearest ten, hundred and thousand, using a variety of tools and models.', 'mathematics', '5', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7273c4fa-dcc4-4a48-b83d-3d596b1d2414', 'MT.5.NS.UN.3', 'Use a variety of tools and strategies to generate, model and classify types of whole numbers (odd, even, prime, and composite); and explain the common features among the numbers in each group, and strategies used.', 'mathematics', '5', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('819c6960-a98f-4622-9aac-908e5d1762a8', 'MT.5.NS.UN.4', 'Use a variety of strategies to generate factors and multiples of a set of whole numbers; and explain strategies employed.', 'mathematics', '5', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e5a56145-1cac-45bd-80ca-e4107d9bc2d6', 'MT.5.NS.UN.5', 'Use a variety of tools and strategies to represent, compare and order decimal numbers represented in tenths and hundredths.', 'mathematics', '5', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9c310271-1d9c-4377-b8ad-6e19442da314', 'MT.5.NS.UN.6', 'Use a variety of tools and strategies to represent, compare and order fractions (proper, improper, mixed numbers) with like and unlike denominators up to 12.', 'mathematics', '5', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('386b911d-bf9f-4f1b-80a4-ef88a0a7b98a', 'MT.5.NS.UN.7', 'Use knowledge of percent (10%, 25%, 50%, 75% and 100%) as a tool to formulate estimation of quantities.', 'mathematics', '5', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4d0bc6d9-9ac2-4c4d-9fdd-c8c0f5c3918c', 'MT.5.UM.LM.1', 'Select, use and justify choice of unit (centimetre, metre and kilometre) used to estimate, measure, and record length and distance; and recognize that objects of the same length can be of different shapes.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c784765c-f64b-4092-a744-e3edce515e9b', 'MT.5.UM.LM.2', 'Use knowledge of relationship between units of length to convert from a larger unit to smaller unit (metres to centimetres; and kilometre to metre) using measures that are equivalent to whole or fractional parts (halves, quarters) of the larger unit.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('6b32dff1-4f3b-423c-9308-dfc4880dc32d', 'MT.5.UM.LM.3', 'Determine the perimeter of regular and irregular plane shapes.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ba341b9e-c632-48c1-bfe6-04b13ca22be9', 'MT.5.UM.LM.4', 'Solve a variety of problems relating to perimeter using several strategies and communicating progress made and challenges encountered.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('01d7ea21-8dc3-46a9-bdbd-a3aa4630ceba', 'MT.5.UM.MA.1', 'Determine the area of surfaces by counting unit squares using a variety of counting strategies.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Materials', 'MA', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7eb38d88-1314-4cf8-b740-de20d017720d', 'MT.5.UM.MA.2', 'Determine the area of regular shapes (squares and rectangles) by counting unit squares; note the dimension of the shapes and begin to use multiplication to make the process more efficient.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Materials', 'MA', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('407d4564-5613-4d35-bf50-40971147f275', 'MT.5.UM.MA.3', 'Solve a variety of problems involving area using several strategies and communicating progress made and challenges encountered.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Materials', 'MA', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ab2f2684-3890-4802-b541-28ab29d7ce0f', 'MT.5.UM.MC.1', 'Select, use and justify choice of unit (millilitre and litre) used to estimate, measure and record capacity, and recognize that containers with different shapes have the same capacity.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9647bb63-f6ab-499f-b6cf-b0a349357342', 'MT.5.UM.MC.2', 'Use knowledge of relationship between litre and millilitre to convert from litre to millilitre, measures that are equivalent to whole or fractional parts (halves, quarters) of a litre.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5a568f95-7bf3-4e03-aed5-067d4319feb9', 'MT.5.UM.MC.3', 'Develop the attitude of reading labels on commonly used packages to tell the capacity (in litre and millilitre) of containers.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('cd6817bd-c801-4faf-a87d-fa673dc89453', 'MT.5.UM.MC.4', 'Solve a variety of problems relating to capacity using several strategies and communicating progress made and challenges encountered.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8bfafb66-5479-4850-8dca-ebea2ab91070', 'MT.5.UM.MM.1', 'Select, use and justify choice of unit (gram and kilogram) used to estimate, measure and record mass, and recognize that objects with the same mass can be of different shapes and sizes.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('cac9876d-3db6-46f7-b2c0-74c917f5e4bb', 'MT.5.UM.MM.2', 'Use knowledge of relationship between gram and kilogram to convert from kilogram to gram using measures that are equivalent to whole or fractional parts (quarters, halves) of a kilogram.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c1a17ef2-eb01-4c1e-8125-7a0f739549a2', 'LA.K.R.WR.1', 'Identify letters and words by name', 'language-arts', 'K', 'Reading and Viewing', 'R', 'Word Recognition', 'WR', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('3aa010ef-507e-4c0e-83d5-0ceb93107d86', 'MT.5.UM.MM.3', 'Develop the attitude of reading labels on commonly used packages to tell the mass (in gram and kilogram) of object.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('08fafc1a-f065-43b4-937b-2afd4a48347c', 'MT.5.UM.MM.4', 'Solve a variety of problems relating to mass of objects using several strategies and communicating progress made and challenges encountered.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('6338de15-b651-42c1-a846-0137f33fa0a1', 'MT.5.UM.MW.1', 'Read and write amounts of money up $10,000 dollars and show an understanding of the value of large amounts of money (up to $10,000) by stating realistic purchasing power a given amount of money.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7321d109-da2e-4457-be71-1afa3573a9f0', 'MT.5.UM.MW.2', 'Use a variety of strategies including concrete materials to add, subtract and multiply money involving dollars and cents not exceeding $1,000 (cents being multiples of 5, 10 and 25); and generate different combinations of notes that give the same amount of money up to $1,000.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e829b879-d432-445b-91db-eb362c3b29d6', 'MT.5.UM.MW.3', 'Read, write and interpret price of items; and use a variety of strategies to calculate the total cost (not exceeding $1,000) of set of items; and make change from amounts up to $100 and explain the effectiveness of approaches used.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c1ab69ee-5da8-4640-b5a5-67de93d6529f', 'MT.5.UM.MW.4', 'Use the terms cost price, selling price, profit and loss as related to buying and selling and make application to simple situations to illustrate the meaning/value of these terms.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c26801d4-a471-4032-b1d9-2fea6b7efffe', 'MT.5.UM.MW.5', 'Use several strategies to create and solve problems involving money transactions.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('47931bc9-cebd-4c93-bd0d-67dee97e16bb', 'MT.5.UM.UT.1', 'Read and record accurately in words and notations various times as display on the analogue and digital clocks.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f69c7332-df93-4101-9c1c-c0ca1a63a651', 'MT.5.UM.UT.2', 'Work in small groups to read and interpret simple calendars, timetables and schedules.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a8ca9c6b-59e6-4aae-8cf8-7f846c90a6de', 'MT.5.UM.UT.3', 'Solve a variety of problems involving time, using several strategies and communicating progress made and challenges encountered.', 'mathematics', '5', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('de24426f-90a3-4eda-aaee-1afe1d7763dd', 'MT.6.DH.DC.1', 'Continue to ask questions suitable for collecting relevant data; identify the population from which data will be collected and accurately record responses to questions.', 'mathematics', '6', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5c1b9948-bcd0-450b-ad44-4ec11d500e2a', 'MT.6.DH.DC.2', 'Continue to collect data from interviews, observations, questionnaires, simple experiments and direct measures.', 'mathematics', '6', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('3fec1bcf-a44c-4864-b3ee-9ca7b8250918', 'MT.6.DH.DC.3', 'Use tally charts and compute facility (spreadsheets, Microsoft excel) to organize collected data.', 'mathematics', '6', 'Data Handling', 'DH', 'Diversity & Classification', 'DC', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4716c320-ba32-493c-8d67-730920abc1d9', 'MT.6.DH.DI.1', 'Read and interpret data presented in tally charts, tables, pictographs, bar graphs, and line graphs.', 'mathematics', '6', 'Data Handling', 'DH', 'Data Interpretation', 'DI', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('92981de2-25ca-4d6e-9c0b-6eb180bf6ba7', 'MT.6.DH.DI.2', 'Identify trends in data presented in tables, pictographs, bar charts', 'mathematics', '6', 'Data Handling', 'DH', 'Data Interpretation', 'DI', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('2f03eb16-c2d5-4985-83c8-0b726d5721d1', 'MT.6.DH.DI.3', 'Use suitable strategies to determine the value of the range, median, mode and mean of a small set of data; and use these values to make relevant comment about the data set.', 'mathematics', '6', 'Data Handling', 'DH', 'Data Interpretation', 'DI', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('46dddc74-18e3-4ede-b8d2-d1f0dc472a24', 'MT.6.DH.DI.4', 'Work in small groups to identify patterns and trends in data and make inferences about from data based on these observations.', 'mathematics', '6', 'Data Handling', 'DH', 'Data Interpretation', 'DI', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c030d796-2d19-47b1-aa24-b4c2dbdcbbed', 'MT.6.DH.DR.1', 'Construct a two-way table with appropriate labelling of rows and columns to organize raw data.', 'mathematics', '6', 'Data Handling', 'DH', 'Data Representation', 'DR', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('38db2a71-0b8f-4e65-ad25-e2b6e3c5d2e4', 'MT.6.DH.DR.2', 'Use grid paper and computer software (Excel program) to create tables, simple vertical and horizontal bar graphs and simple line graphs.', 'mathematics', '6', 'Data Handling', 'DH', 'Data Representation', 'DR', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ed4238fe-144e-483e-8b9a-584fbb6701a6', 'MT.6.DH.DR.3', 'Select an appropriate method (table, picture graph, bar graphs or line graph) and suitable scale for representing data and give reasons for choice.', 'mathematics', '6', 'Data Handling', 'DH', 'Data Representation', 'DR', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1503e15e-6767-4f80-abcb-d218151b9ac4', 'MT.6.GT.DS.1', 'Identify, describe and represent the position of points within the first quadrant of the Cartesian Plane.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('3a5dc3ef-2131-410e-843a-a34d3461d7a4', 'MT.6.GT.DS.2', 'Use pencil and paper and computer software to construct 2D shapes and translate these shapes on coordinated grid paper.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f71d9e80-9ea9-4978-a7c5-a04826d02e5f', 'MT.6.GT.DS.3', 'Use knowledge of properties of triangles, and quadrilateral to predict the position(s) of one or two missing vertices of these shapes drawn within the first quadrant of the Cartesian plane.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('2b047728-d250-4581-8df2-9981af080290', 'MT.6.GT.DS.4', 'Work in small groups to predict position and size of a shape before translation or reflection; carry out the translation or reflection; and discuss the result with their predictions.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('04f0420a-ac64-4a14-86d8-fb3f67c214f7', 'MT.6.GT.DS.5', 'Use and follow simple instructions relating to directions to draw plane shapes', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('2778d7e7-36b8-4cf2-949c-537d0aa25752', 'MT.6.GT.DS.6', 'Use a variety of strategies to solve problems relating to position and direction.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Directional Sense', 'DS', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e3218ff3-5651-4d94-b908-895fcc44e503', 'MT.6.GT.PL.1', 'Recognize that line segments, rays and lines are one dimensional while a plane is two dimensional.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Points and Lines', 'PL', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('0dbc0d6b-513d-4760-9e8f-76ee3fbe5145', 'MT.6.GT.PL.2', 'Use examples to illustrate and distinguish between parallel and intersecting; and vertical and horizontal lines.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Points and Lines', 'PL', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('09df3585-e2cc-45fb-99b4-212009625072', 'MT.6.GT.PS.1', 'Describe a polygon as a closed figure bounded by straight sides; name and sketch polygons with up six sides', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7d050635-fc03-4565-9882-8780c33fdb55', 'MT.6.GT.PS.2', 'Classify quadrilaterals based on their linear properties (rectangles, squares, parallelograms, trapeziums, kites); and explain reasons for classifications.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1a0aabb5-00f2-41c6-b330-6a45fa15db09', 'MT.6.GT.PS.3', 'Determine the number of lines of symmetry of given shapes', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('02e93cae-1c15-4690-987e-23bda19597fc', 'MT.6.GT.PS.4', 'Classify triangles based on their linear and angular properties (right angled, obtuse angled; equilateral, isosceles and scalene).', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b1af13cb-5171-45b8-b570-eef23a8516f0', 'MT.6.GT.PS.5', 'Work in small groups to investigate and discuss the relationship of the diameter and other parts of the circle (twice the radius; longest chord; divides circle into two semi-circles; line of symmetry of circle).', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('96d36a8d-d5d8-43cc-a6bf-14686f70804f', 'MT.6.GT.PS.6', 'Apply knowledge of properties of 2-D shapes to calculate missing angles and sides.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('507537cc-d3d1-4975-8303-68e9810b36c5', 'MT.6.GT.PS.7', 'Use a variety of strategies to solve problems related to 2-D shapes.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Physical Science', 'PS', NULL, '5-6', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0e21154f-4631-4423-ab74-4585c18090ff', 'MT.6.GT.SS.1', 'Continue to use mathematics language (such as parallel faces, circular faces, opposite faces, curved surface, flat faces, curved edges) to describe and compare properties of 3D shapes.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('3055479f-1006-4d6b-9281-44e9b5c3aa14', 'MT.6.GT.SS.2', 'Work in small groups to investigate different outlines of nets for cubes and cuboids; note and explain patterns observed in the different arrangements of the faces put together to form the net of cubes and cuboids.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('6f9d6b1c-563e-4c07-b85a-f0da94de0d37', 'MT.6.GT.SS.3', 'Work in small groups to make predictions and compare predictions with results when a given 3D shape is cut parallel to one of its faces.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('473f140c-5cee-4f0d-809e-55e3c5841581', 'MT.6.GT.SS.4', 'Use a variety of strategies to explore and respond to problems based on 3D shapes and their nets.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Solar System', 'SS', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4d1b1d75-d5eb-4df5-9b68-41fac4724cb5', 'MT.6.GT.UA.1', 'Use terms (such as acute, right angle, obtuse, straight and reflex) to describe and classify angles based on their sizes.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('31292dc6-9974-4c82-aca1-5b9153dd5f37', 'MT.6.GT.UA.2', 'Continue to apply knowledge of measure and types of angles and the angular properties of triangles, squares and rectangles to estimate and calculate missing angles.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b867e30b-1f5e-48b8-bee8-d95b61f07224', 'MT.6.GT.UA.3', 'Recognize that four quarter turns equal a whole turn; and connect this knowledge with the fact that the sum of angles at the center of a circle equals 360°.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('01b65dec-bb25-4d92-967a-6da356f51c3b', 'MT.6.GT.UA.4', 'Use a variety of strategies (drawing, trial and error; looking for patterns; practical work) to respond to problems involving angles.', 'mathematics', '6', 'Geometric Thinking', 'GT', 'Understanding Angles', 'UA', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('624d5c1a-6912-497c-9497-dbf94046308d', 'MT.6.NS.NP.1', 'Continue to complete, extend and describe (in words) given whole number patterns obtained from counting forward or backward, doubling or halving and adding, subtracting or multiplying by a constant.', 'mathematics', '6', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0e0f2523-e90b-4376-83f2-77e0c2c826f1', 'MT.6.NS.NP.2', 'Continue to generate a table of values to summarise results obtained from a pattern resulting from adding, subtracting or multiplying whole numbers by a constant to get successive terms.', 'mathematics', '6', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d91284c0-3a1b-4672-9e5d-511e8cf38fb0', 'MT.6.NS.NP.3', 'By analysing the results obtained from computing with whole numbers, continue to formulate and use the generalizations', 'mathematics', '6', 'Number Sense', 'NS', 'Number Patterns', 'NP', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ec616d56-39f9-49b8-90e1-56f8f68f4cd5', 'MT.6.NS.OS.1', 'Continue to use a variety of mental strategies to add, subtract, multiply and divide whole numbers', 'mathematics', '6', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4cf6dc14-7555-43d1-864b-262fe9f0d370', 'MT.6.NS.OS.2', 'Use a variety of mental and written strategies to estimate and perform addition and subtraction of whole numbers up to 5-digit without and with regrouping.', 'mathematics', '6', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ec9a53c5-062a-4717-ac2c-5fc485ee6577', 'MT.6.NS.OS.3', 'Multiply and divide whole numbers by 10, 100, 1,000, 10,000, use calculator to check for pattern, and use identified patterns to formulate generalizations.', 'mathematics', '6', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0061f53a-db17-41f4-bbd0-86768dd375d6', 'MT.6.NS.OS.4', 'Use a variety of strategies to multiply a 3-digit number by a 2 or 3-digit number and to divide a three-digit number by a two-digit number.', 'mathematics', '6', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a9c657b9-8fc7-4220-99d5-c33c6841a983', 'MT.6.NS.OS.5', 'Create and solve a variety of one and two step problems involving addition, subtraction, multiplication and division and develop the skill of checking the reasonableness of worked solution against initial estimated result.', 'mathematics', '6', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ec8cf907-19e2-4092-ba06-b6afdca6b45c', 'MT.6.NS.OS.6', 'Use a variety of tools and strategies, including the calculator, to add, subtract, multiply and divide decimal numbers to tenths.', 'mathematics', '6', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('30b78110-87c6-4a40-ac12-a23afc2af0ab', 'MT.6.NS.OS.7', 'Use pictorial models and questions to interpret multiplication of a whole number by a fraction and the product of a pair of simple fractions', 'mathematics', '6', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d39d2ee4-6229-49d9-b42e-9c421394ad0d', 'MT.6.NS.OS.8', 'Use a variety of tools and strategies to add and subtract two fractions (proper, improper mixed numbers) where one denominator is a multiple of the other.', 'mathematics', '6', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a1ba7cbf-cd3b-4966-bc8a-4fc7dcd71306', 'MT.6.NS.OS.9', 'Use pictorial models to interpret multiplication of a whole number by a fraction and the product of a pair of simple fractions', 'mathematics', '6', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('bb2f4760-1419-43b0-9ede-9cbbaaf72249', 'LA.K.LS.SI.13', 'Converse politely with teacher, other adults and classmates in small groups or a one-to-one basis', 'language-arts', 'K', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 13, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('dbd289fc-ffa5-4c4e-84ba-692d5c223737', 'MT.6.NS.OS.10', 'Count forward in fractional parts by halves, thirds, quarters, fifths, sixths, eighths and tenths beyond one whole; and count forward in decimal by tenths and hundredths using numbers expressed to up to two decimal places.', 'mathematics', '6', 'Number Sense', 'NS', 'Operational Sense', 'OS', NULL, '5-6', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('797364c7-8e05-4e09-b211-8d845e279926', 'MT.6.NS.PR.1', 'Work in small groups, using concrete materials and calculator, to investigate and note the relationship among percent, decimal numbers and fractions (with denominators 2, 4, 5, 10, 20, 25, 50 and 100).', 'mathematics', '6', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0ed0308f-7be3-4dc0-9c56-146cb75b753b', 'MT.6.NS.PR.2', 'Illustrate and explain the concept of percent larger than 100%; find a percent of a quantity; express one quantity as a percent of another; and convert among percent, fraction and decimal.', 'mathematics', '6', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('6cf9bb98-c959-4927-b37b-aa14e735c6cc', 'MT.6.NS.PR.3', 'Read, represent, simplify and interpret ratio as related to comparison of two quantities of the same type found in real-life contexts.', 'mathematics', '6', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d8dc8eba-077a-46a2-be31-5fa0044de230', 'MT.6.NS.PR.4', 'Use a variety of strategies and models to Interpret and explain the relationship that exists among a ratio, percent, fraction and decimal, and use this knowledge to convert from one to the others.', 'mathematics', '6', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e0302f8c-d5a5-4dfc-8f4f-c3820203e8cd', 'MT.6.NS.PR.5', 'Share a quantity into two parts according to a given ratio.', 'mathematics', '6', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9b490e2b-464b-4ce4-9ed2-c5b1127072ad', 'MT.6.NS.PR.6', 'Use a variety of strategies to solve real life problems involving fractions, percent and ratio. And reflect on the progress made and challenges encountered.', 'mathematics', '6', 'Number Sense', 'NS', 'Punctuality and Regularity', 'PR', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5e42c96f-3683-48b7-a18d-f9b6b03c5076', 'MT.6.NS.UN.1', 'Read, write, count, expand, and compare numbers up to seven digits, using a variety of tools and models; and differentiate among face value, place value and total value of each digit', 'mathematics', '6', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ab995854-7474-4006-bf97-2fc53d27abdf', 'MT.6.NS.UN.2', 'Round numbers to nearest ten, hundred and thousand, using a variety of tools and models.', 'mathematics', '6', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f9b2aa2e-c9ac-4ad0-a7f8-51bfcf018438', 'MT.6.NS.UN.3', 'Create and solve problems involving ordinal numbers', 'mathematics', '6', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0c4706e6-fff8-48ff-b9d8-921a79b4811f', 'MT.6.NS.UN.4', 'Use a variety of tools and strategies to generate, model and classify types of whole numbers (odd, even, prime, composite, and squares); and explain the common features among the numbers in each group, and strategies used.', 'mathematics', '6', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a1f25b85-d92c-4d86-b430-0064da752c66', 'MT.6.NS.UN.5', 'Use a variety of strategies to generate factors, common factors, highest common factors, multiples, common multiples, lowest common multiples of a set of whole numbers; and explain strategies employed.', 'mathematics', '6', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ecb6ae0a-aca6-4a8c-8340-86d88de718d4', 'MT.6.NS.UN.6', 'Use a variety of tools and strategies to represent, compare and order decimal numbers represented in tenths and hundredths.', 'mathematics', '6', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d152f73a-a7ec-4247-a3f2-4fa86f43777c', 'MT.6.NS.UN.7', 'Use a variety of tools and strategies to represent, compare, classify and order fractions (proper, improper, mixed numbers) with like and unlike denominators up to 12.', 'mathematics', '6', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5be3f769-1c49-4417-a07d-28d78a98c1cb', 'MT.6.NS.UN.8', 'Use knowledge of percent (10%, 20%, 25%, 50%, 75% and 100%) as a tool to formulate estimation of quantities.', 'mathematics', '6', 'Number Sense', 'NS', 'Understanding Numbers', 'UN', NULL, '5-6', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('cad45f5a-c2d9-409b-b8f8-b7410b66689d', 'MT.6.UM.LM.1', 'Select, use and justify choice of instrument and unit (millimetre, centimetre, metre and kilometre) to measure length and distance and explain strategy used.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('100658ed-a25d-4e3a-83f4-98fcb89711ce', 'MT.6.UM.LM.2', 'Work in small groups, use knowledge of relationship between units of length to convert from a larger unit to smaller unit (metres to centimetres; and kilometre to metre) using measures that are equivalent to whole or fractional parts (halves, quarters and tenths) parts of the larger unit.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('50178ab8-7d25-4360-9b9e-189e148cb699', 'MT.6.UM.LM.3', 'Work in small groups, use the approximate equivalence of 1 inch ≈ 2.5 centimetre to produce other equivalent measures between whole inch measures and centimetre up to 1 yard (3feet) ≈ 90 centimetres.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('68478ffd-aaf2-4450-96df-587295ada208', 'MT.6.UM.LM.4', 'Determine the perimeter of regular and irregular plane shapes.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5834d4bb-8f19-42ec-9d6c-cae6b53fd5aa', 'MT.6.UM.LM.5', 'Begin to use algebraic thinking in conjunction with other strategies to determine one or two missing sides in a plane shape given the perimeter and information about the other sides.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Linear Measurement', 'LM', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9ff90cd8-5340-420d-bb8a-c723a597a3d0', 'MT.6.UM.MA.1', 'Determine the area of right angled triangles by counting unit squares and relate the area of right angled triangle to its corresponding rectangle (with sides equal to base and height of the triangle).', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Materials', 'MA', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('de213db7-0fe1-41e7-8d72-a64e12558579', 'MT.6.UM.MA.2', 'Determine the total area by counting unit squares enclosed by compound shapes (made up of rectangles, squares and right angled triangles).', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Materials', 'MA', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('98486857-05d0-460d-aa8b-c9578a0849b3', 'MT.6.UM.MA.3', 'Work in small groups to investigate situations relating to rectangles with same perimeter but different area.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Materials', 'MA', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('911612c5-1f05-4a7e-ab10-421fb477bcc8', 'MT.6.UM.MA.4', 'Solve one and two step problems involving the area of rectangles and squares using several strategies and compare the effectiveness of the different strategies.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Materials', 'MA', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('dfd2383d-0918-4e23-9c90-164a856c4c09', 'MT.6.UM.MC.1', 'Select, use and justify choice of unit (millilitre and litre) used to estimate, measure and record capacity, and recognize that containers with different shapes have the same capacity.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('37e893a4-c584-415a-a02d-710f1275276d', 'LA.K.LS.SI.14', 'Speak clearly enough to be understood by peers and teacher', 'language-arts', 'K', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 14, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9cea477d-3f80-41c5-8939-2d57b74b4138', 'MT.6.UM.MC.2', 'Use knowledge of relationship between litre and millilitre to convert from litre to millilitre, measures that are equivalent to whole or fractional parts (halves, quarters and tenths) of a litre.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d1cb86d8-22ce-4760-aa2e-a176ac075a71', 'MT.6.UM.MC.3', 'Use the approximate equivalence of 1 gallon ≈ 3.8 litres to produce other equivalent measure between whole gallon (multiples of 10 up 100) and litres.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('cfe108e8-5a49-42c8-bc70-f4e9d204861d', 'MT.6.UM.MC.4', 'Continue to practice reading and interpreting labels on commonly used packages to tell the capacity (in litre and millilitre) of containers; and deduce that containers of different shapes could have the same capacity.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('2e9c9e7d-4d2b-499f-b8ba-8bd2869329c2', 'MT.6.UM.MC.5', 'Use a variety of strategies to solve problems related to capacity; and explain and compare strategies used.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Measuring Capacity', 'MC', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8abc2132-7c05-47a6-87f4-5f04c1f0ab96', 'MT.6.UM.MM.1', 'Select, use and justify choice of unit (gram and kilogram) used to estimate, measure and record mass; and recognize that objects with the same mass can be of different shapes and sizes.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('54b195a1-5ba3-4801-bf4a-263bbb1a6f7f', 'MT.6.UM.MM.2', 'Use knowledge of relationship between kilogram and gram to convert from kilogram to gram using measures that are equivalent to whole or fractional parts (halves, quarters and tenths) of a kilogram.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f557ca09-e4dc-4fee-aa03-4df89730616f', 'MT.6.UM.MM.3', 'Use the approximate equivalence of 1 kilogram ≈ 2.2 pounds to generate other equivalent measures between whole kilogram and pound.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('48473566-230a-4ce4-81c1-e9dc211c7b1f', 'MT.6.UM.MM.4', 'Continue to practice reading and interpreting labels on commonly used packages to tell the mass (in gram and kilogram) of objects; and deduce that objects of different shapes could have the same mass.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('be75096f-da08-48a5-80fe-d69970a128d1', 'MT.6.UM.MM.5', 'Use a variety of strategies to solve problems related to mass and explain strategies used.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Matter & Materials', 'MM', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4353baf4-14a5-4285-b839-e5ac47a0f121', 'MT.6.UM.MW.1', 'Read and write amounts of money up to $100,000 dollars and show an understanding of value of a large amounts of money (up to $100,000) by stating purchasing power the amount.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7485eb2b-614f-4762-aa91-9e471f731e4a', 'MT.6.UM.MW.2', 'Use a variety of strategies, including concrete materials, to perform the four operations on money; and generate different combination of notes that give the same amount of money up to $1,000.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a51cca59-e8a8-4469-8887-f412bbdd97f3', 'MT.6.UM.MW.3', 'Read, write and interpret price of items; and use a variety of strategies to calculate the total cost (not exceeding $10,000) of set of items and make change from amounts up to $1,000 and explain the effectiveness of the strategies used.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1d90da00-87a1-49d9-ac24-e83d50415e33', 'MT.6.UM.MW.4', 'Use the terms cost price, selling price, profit, loss, discount, tax, and interest as related to buying and selling; and apply different strategies in simple situations to determine and compare the value of these terms.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d3a2747e-749e-4e68-8c61-ca89202bebed', 'MT.6.UM.MW.5', 'Round money amounts to the nearest 5-cent; and justify strategies used in deciding when to ''round up'' and when to ''round down''.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ae420868-1137-482b-9210-0b57c2edbda1', 'MT.6.UM.MW.6', 'Use several strategies to create and solve problems involving money transactions.', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Money Works', 'MW', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e4f9adef-f59a-4dc8-9ba8-d89517d78d66', 'MT.6.UM.UT.1', 'Tell the time accurately using words and different notations (am/pm and 24-hour).', 'mathematics', '6', 'Understanding Measurement', 'UM', 'Use of Technology', 'UT', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
