  ('83a1e301-4d10-4ed8-8fcc-76ce89750ab7', 'LA.K.WR.AI.2', 'Demonstrate an interest in working on writing letters and words', 'language-arts', 'K', 'Writing', 'WR', 'Attitudes and Interests', 'AI', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('28f8a33e-c9c0-4da7-ad92-50e221d66112', 'LA.K.WR.AI.3', 'Demonstrate pleasure in talking about their writing', 'language-arts', 'K', 'Writing', 'WR', 'Attitudes and Interests', 'AI', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4d0331f9-3682-4a88-b9e2-ab41ae84a0fc', 'LA.K.WR.AI.4', 'Demonstrate a determination in learning to spell high frequently words', 'language-arts', 'K', 'Writing', 'WR', 'Attitudes and Interests', 'AI', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1f9e96b0-249e-4c05-bfbc-703d37ba308a', 'LA.K.WR.AI.5', 'Display a cooperative spirit by working with peers', 'language-arts', 'K', 'Writing', 'WR', 'Attitudes and Interests', 'AI', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1d4f6ea4-a2f5-44c6-8984-1427f70f9352', 'LA.K.WR.AI.6', 'Display a sense of pride in their writing', 'language-arts', 'K', 'Writing', 'WR', 'Attitudes and Interests', 'AI', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('624495e6-6c56-4f69-b9cb-d093b6b16b09', 'LA.1.LS.LC.1', 'Use strategies when listening to make and simplify meaning including asking questions, recalling ideas, focusing on the speaker, preparing for listening', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c327259b-bb41-435a-86f3-39e3ab835c4a', 'LA.1.LS.LC.2', 'Demonstrate enriched vocabulary knowledge and usage in order to widen and explore meaning.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('41774c12-f5e8-4b5f-a09d-bff5c1050880', 'LA.1.LS.LC.3', 'Listen to and retell stories, express an opinion on likes and dislikes about stories read or read to.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b154a317-6ca4-4132-ace6-8288cdb8ae44', 'LA.1.LS.LC.4', 'Show an understanding of the information and ideas in oral texts by telling the story or restating the information including the main concepts.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('171d4d0d-3f3b-49e1-8c87-ac8bdc10930a', 'LA.1.LS.LC.5', 'Use stated or implied information and ideas in oral text, initially with support and direction to make simple deductions and sensible predictions.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('92cb8448-1a3e-4951-a641-3b2126e7553e', 'LA.1.LS.LC.6', 'Ask and answer questions about important aspects in a text, read aloud or information described orally or through other media', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b5c9e00a-03d2-4c47-906f-5a4ed849b0a8', 'LA.1.LS.LC.7', 'Listen to understand cause and effect relationships.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('271a6ed9-8dd4-4c30-ac47-8701e20236e7', 'LA.1.LS.LC.8', 'Listen to a selection and draw conclusions about the selection.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1d3840aa-de6f-4e24-9fb0-c71367a66328', 'LA.1.LS.LC.9', 'Listen to identify the order of events in a selection', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7b45d622-1361-41ac-adbf-a6cb8c731c66', 'LA.1.LS.LC.10', 'Listen to supply the missing details in a known or read to story', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ff6567fb-dec0-4030-964f-2a938099bb67', 'LA.1.LS.LC.11', 'Listen to an account of an event, story or selection in order to make a prediction.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b61e3831-8e77-4b42-8cb5-68d19ea408b8', 'LA.1.LS.LC.12', 'Listen to differentiate between make-believe and truth.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 12, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('873e3705-5774-4a99-9027-792fe94294e6', 'LA.1.LS.LC.13', 'Listen, discuss and give an opinion in reply to views articulated by others.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 13, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c671a4b5-3af6-48ff-846e-2b158783809e', 'LA.1.LS.GI.1', 'Take and transfer simple messages', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a46a2326-8d4f-403a-aecb-fd1d84a2f9d8', 'LA.1.LS.GI.2', 'Use speaking to explore, articulate and offer ideas, information and reactions by staying on topic, using descriptive words, telling and retelling stories and experiences in rational sequence.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b70cba63-9afa-4de6-947c-4d18d054d1b1', 'LA.2.LS.LC.2', 'Make inferences about characters’ feelings or the story problem.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'LC', 'LC', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('55eeefe8-b625-4256-872c-9d48c52d87b0', 'LA.1.LS.GI.3', 'Use strategies when expressing and presenting ideas, information and feelings, including retrieving previous knowledge, predicting some things the listeners need to know.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('601dc2ff-5cac-48cd-973d-b633f3741312', 'LA.1.LS.GI.4', 'Concentrate on descriptive features and begin to be clear in relation to people and places, times, procedures, events etc.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('20ab2522-75ee-4350-86af-52fd0fc5e0d4', 'LA.1.LS.GI.5', 'Create and tell stories', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4b9a6d93-e0d9-41e4-8bf6-6e4f37fe3707', 'LA.1.LS.GI.6', 'Describe people, places and things and events with relevant details, expressing ideas and feelings clearly.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7d16d29f-5bf7-425d-91ad-fb65ba01c2e5', 'LA.1.LS.GI.7', 'Ask for and give factual information about a selected topic.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4ff529ff-83f0-4208-9acf-72edb729811a', 'LA.1.LS.GI.8', 'Produce complete sentences when suitable to task and setting', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a506319e-dddc-4d4f-bb81-5846ad67697b', 'LA.1.LS.GI.9', 'Give and get information, ideas and opinions.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f320ce8c-5e26-433c-b974-8466cc89d34b', 'LA.1.LS.SI.1', 'Use listening and speaking to cooperate with others in order to contribute to class goals, exchange opinions on a topic, make associations, complete task and participate in play.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('596214e3-e6ff-4361-ab6c-1e636df6d93e', 'LA.1.LS.SI.2', 'Listen to identify the mood and feelings of a speaker.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5e2c3712-d861-493f-b0da-e6323093333f', 'LA.1.LS.SI.3', 'Use correct forms of the language to greet, thank, make a request, apologise and issue an invitation.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('69c15e0b-ad89-4fd1-87b7-3fa2e8d420f5', 'LA.1.LS.SI.4', 'Use strategies when working together with others, including taking turns as listener and speaker', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1f7f6913-d85e-492a-8621-fb35a3912014', 'LA.1.LS.SI.5', 'Listen for a range of purposes and exhibit comprehension by retelling or restating, following a two-step instruction, asking questions for clarification and understanding, sharing associations made.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7f2fa7cc-4e17-476e-a301-9258266b56a5', 'LA.1.LS.SI.6', 'Engage in speaking and listening activities to develop a deeper understanding of text e.g. listening to the telling of a story from an oral custom', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7cb01c78-fb5c-4746-92e8-ab86167ded79', 'LA.1.LS.SI.7', 'Use listening and speaking in group activities to foster thinking by recognising relationships and gaining new ideas', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('52ecba7d-6d78-4520-9f46-61613679f13a', 'LA.1.LS.SI.8', 'Use the characteristics of oral language to express and develop meaning including using most words correctly and expressing ideas clearly, e.g. using simple linking words, pronouns and simple tense forms', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5835d564-8a73-4869-931a-4b846bbdc935', 'LA.1.LS.SI.9', 'Tryout different voices in role playing', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('878d870e-033c-4a9b-9c46-dfa5dc512430', 'LA.1.LS.SI.10', 'Identify some non-verbal cues (e.g. facial expressions, gestures etc.) and use them in oral communication suitably and with thoughtfulness towards ethnic differences to help communicate their meaning.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('76dd489d-2b69-4d98-a92a-49d98eeb7a78', 'LA.1.LS.SI.11', 'Expand on others’ talk in conversations by reacting to the remarks of others through several interactions.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('fcb8904e-c1c4-4a97-9377-ba33c70f6636', 'LA.1.LS.SI.12', 'Listen to others’ and share personal experiences, news etc. with which they are familiar', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 12, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0e59ed49-8f46-4f15-ad1d-4dc5cfce2fe9', 'LA.1.LS.SI.13', 'Listen to discern the differences between Standard English and native language.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 13, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4356ed48-d883-410e-a59f-c9bccb251613', 'LA.1.LS.SI.14', 'Follow agreed upon rules for conversations', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 14, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d0397a57-6887-4bb8-b346-eaabf0d944db', 'LA.1.LS.SI.15', 'Engage in oral activities organized for the class.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 15, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5b16221e-a90d-4bb7-af77-1ba16e4dea04', 'LA.1.LS.SI.16', 'Listen attentively during conversational exchanges and oral presentations.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 16, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d578d241-b98a-4376-8dd0-16bad1999ef6', 'LA.1.LS.LR.1', 'Think about on their own speaking and listening to pinpoint their strengths and weaknesses and to debate characteristics of good speakers and listeners.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LR', 'LR', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('29f2f051-b2ec-4725-91f0-8d604ad60341', 'LA.1.LS.LR.2', 'Reflect on and talk about a wide variety of routine occurrences and feelings', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LR', 'LR', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7561d199-edeb-4cc8-abae-8cbc5c77a62b', 'LA.1.LS.LE.1', 'Recite poems, jingles, limericks paying special attention to the rhyme and rhythm of the language.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LE', 'LE', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('803a11a1-6cd4-4461-a347-ca7033e37827', 'LA.1.LS.LE.2', 'Listen to and recite jingles, poems, rhymes, limericks and express a personal reaction to selections.', 'language-arts', '1', 'Listening and Speaking', 'LS', 'LE', 'LE', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('dcb11c5d-04fe-4285-aca3-83f99ca0e602', 'LA.1.R.PA.1', 'Show phonological perception by identifying and generating rhyming words, using sound and segmenting and sound blending of syllable and phonemes in words', 'language-arts', '1', 'Reading and Viewing', 'R', 'Phonological Awareness', 'PA', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('84b165cd-6ebc-4047-b0bc-852792902705', 'LA.1.R.PA.2', 'Isolate and pronounce initial, medial and final sounds in a single-syllable word.', 'language-arts', '1', 'Reading and Viewing', 'R', 'Phonological Awareness', 'PA', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('794b7772-91ff-4fd4-b574-9d41fcd2ebfc', 'LA.1.R.PA.3', 'Recognize the same sounds in different words', 'language-arts', '1', 'Reading and Viewing', 'R', 'Phonological Awareness', 'PA', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('56bbda05-224e-4e57-b939-af1d289b66de', 'LA.1.R.PA.4', 'Pupil will recognize individual sounds in a word', 'language-arts', '1', 'Reading and Viewing', 'R', 'Phonological Awareness', 'PA', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('83174d04-008e-47c4-8f44-292a3819b96f', 'LA.2.R.WR.11', 'Read environmental signs and names of places.', 'language-arts', '2', 'Reading and Viewing', 'R', 'Word Recognition', 'WR', '', 'K-2', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('bb45f9e5-d88d-4edc-8fee-777226f38085', 'LA.1.R.PA.5', 'Pupil will recognize the word in a set of three or four words that has the “odd” sound', 'language-arts', '1', 'Reading and Viewing', 'R', 'Phonological Awareness', 'PA', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1ac7fe63-7270-4032-beec-94298997e89d', 'LA.1.R.PA.6', 'Pupil will orally produce single-syllable words by blending phonemes in spoken single-syllable words.', 'language-arts', '1', 'Reading and Viewing', 'R', 'Phonological Awareness', 'PA', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a0bb2569-6ca9-40ba-adf9-076c26d28251', 'LA.1.R.PA.7', 'Pupil will break a given word into its separate sounds and say each sound as it is tapped out, counted or signaled', 'language-arts', '1', 'Reading and Viewing', 'R', 'Phonological Awareness', 'PA', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d9cbb9da-ea1a-41a3-ae3c-23600a81bce5', 'LA.1.R.PA.8', 'Pupil will recognize the word that remains when a phoneme is removed from another word.', 'language-arts', '1', 'Reading and Viewing', 'R', 'Phonological Awareness', 'PA', '', 'K-2', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c21bf7f9-a2e9-4f90-b326-c7dfa0271020', 'LA.1.R.PA.9', 'Pupil will make a new word by adding a phoneme to an existing word', 'language-arts', '1', 'Reading and Viewing', 'R', 'Phonological Awareness', 'PA', '', 'K-2', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9f06a5f7-7bcc-4db7-8317-76da8e825e71', 'LA.1.R.PA.10', 'Pupil will substitute one phoneme for another to make a new word.', 'language-arts', '1', 'Reading and Viewing', 'R', 'Phonological Awareness', 'PA', '', 'K-2', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
