  ('f46d7c79-a4e8-45dc-904e-bb6d20f43de8', 'LA.1.WR.WP.2', 'Experience how a story structure is organized by reading and listening to fiction.', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a4c18d0a-8b35-4baf-b5d6-2b9de61085ab', 'LA.1.WR.WP.3', 'Use pictures, stories, poems and actual events as resources for ideas for writing.', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f4572056-50a3-475c-829c-4708cc09e360', 'LA.1.WR.WP.4', 'Choose topics to write about using a variety of genres (e.g. a story, an invitation, a letter)', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b184b0ab-8d5a-438f-9142-3f5d2c3a73b5', 'LA.1.WR.WP.5', 'Identify the topic, purpose, audience and form for writing, initially with support and direction', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9c3857a2-af5a-46b0-88c3-df703346b83c', 'LA.1.WR.WP.6', 'Brainstorm to produce ideas for writing,', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7727d99b-533d-481c-b8a3-b69a6843993a', 'LA.1.WR.WP.7', 'Generate ideas about a potential topic using a variety of strategies and resources.', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e338b324-1347-42e8-a2b9-4609fc440c8a', 'LA.1.WR.WP.8', 'Gather information to support ideas for writing in a variety of ways and/or from a variety of sources.', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ad4ff126-d9a7-4f8e-803d-8abb76d996c1', 'LA.1.WR.WP.9', 'Sort ideas and information for their writing in a variety of ways with support and direction (e.g. using pictures, labels, key words etc.)', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a2cf56d4-058b-4fe1-8092-9cddf4d7adff', 'LA.1.WR.WP.10', 'With guidance and support from teacher focus on a topic, respond to questions and suggestions from peers and add details to strengthen writing as needed', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('edb0a21b-12eb-440d-857e-01b59e66aa97', 'LA.1.WR.WP.11', 'Identify and order main ideas and supporting details, initially with support and direction using simple graphic organisers. (E.g. story ladder, sequence chart, etc.)', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8def9796-1977-4dd2-b463-cd9ea570c3cd', 'LA.1.WR.WP.12', 'Write simple but complete sentences that make sense.', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 12, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0af08777-db19-4fd1-8ad6-2f3849fecc0d', 'LA.1.WR.WP.13', 'Write simple sentences and add words to them to extend their meanings.', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 13, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('6438daf7-3218-4ea4-a519-e489256d9285', 'LA.1.WR.WP.14', 'Write regularly for different audiences. (e.g. personal purposes, the teacher, other children, the family)', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 14, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d0d2c28a-54b0-410c-a199-74a8d7b14a6e', 'LA.1.WR.WP.15', 'Begin to establish a personal voice in their writing by using pictures and words that convey their attitude or feelings towards the subject or audience', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 15, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9703516a-1642-4a69-9b81-fe4e5bb03fbd', 'LA.1.WR.WP.16', 'Realise that first attempts at writing are not necessarily the finished product and learn to undertake second drafts in order to improve writing.', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 16, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e6faddfd-6aae-4438-ac79-064d27810a72', 'LA.1.WR.WP.17', 'Make simple revisions to improve the content, clarity and interest of their written work. (E.g. cut out words, re-order words, etc.)', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 17, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('6b48ee6b-fdc3-43fa-b22c-b5bbbc1720c0', 'LA.1.WR.WP.18', 'Proofread and correct their writing, using a simple checklist or a few questions given by teacher for reference.', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 18, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('77fb5df5-73d5-4c60-85ea-b4fef7ff4e3b', 'LA.1.WR.WP.19', 'Write narratives in which they recount two or more appropriately sequenced events. Include some details regarding what happened, use temporal words to signal event order and to provide some of closure', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 19, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('533fa0f3-4c8e-48fe-a8b6-37792128cbc6', 'LA.1.WR.WP.20', 'Engage in expository writing – How to make or do something', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 20, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e36d9b17-0b36-47fd-9841-06602ccb17b8', 'LA.1.WR.WP.21', 'Produce pieces of work to meet criteria identified by the teacher based on the expectations', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 21, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('60dc919a-ddab-40af-8d81-c6fd4fb7d5f9', 'LA.1.WR.WP.22', 'Use familiar words and phrases to convey a clear meaning, e.g. descriptive adjectives', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 22, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f0767b6a-79cd-41f7-b300-f8a6bfa7faf8', 'LA.1.WR.WP.24', 'Write important personal information, e.g. address, telephone number etc.', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 24, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('74dd07dd-9112-46bb-9c5f-bae4fb3ce51e', 'LA.1.WR.WP.25', 'Write to experiment with different forms e.g. labels invitations, songs, poems, stories etc.', 'language-arts', '1', 'Writing', 'WR', 'WP', 'WP', '', 'K-2', 25, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4d45ee40-f899-4c35-8eed-d38e5dda25f1', 'LA.1.WR.WC.1', 'Use left to right and top to bottom orientation on page', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a76054bc-06a8-4507-bdff-d195d0d2ca1e', 'LA.1.WR.WC.2', 'Begin to write legibly and in an appropriate size for grade level.', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0e44f46f-8fee-4aea-a1dd-1885412ff56f', 'LA.1.WR.WC.3', 'Understand that the conventions of punctuations help to make meaning clearer in writing.', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('3b05627d-e584-4d3a-af49-efb1c1ca2cec', 'LA.1.WR.WC.4', 'Use punctuation to help communicate the intended meaning with a focus on capital letters, period, question mark and exclamation mark.', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1161d20d-78d0-4702-a95a-bd6a51fb8308', 'LA.1.WR.WC.5', 'Use appropriate spelling as an interim measure in mastering the convention of spelling.', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('aef2bc26-8b8f-4690-95b8-389b3afc0a92', 'LA.1.WR.WC.6', 'Spell correctly a range of familiar and regularly occurring words and use a variety of sources as aids to spelling. (e.g. picture dictionary, word walls etc.)', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('037e53ff-208e-4336-ae5f-48da97ce4e33', 'LA.1.WR.WC.7', 'Spell words in a recognizable way based on an awareness of the most common strings and patterns.', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('80b1f1a7-b880-410a-9414-2c8bd055a67e', 'LA.1.WR.WC.8', 'Try at spelling high frequency words in autonomous writing.', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('3aeb009e-8a78-4f4e-87c4-2c2b9df49868', 'LA.1.WR.WC.9', 'Identify and use common prefixes and suffixes', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9ae523e5-84a6-401e-8727-490a84a36f65', 'LA.1.WR.WC.10', 'Use parts of speech appropriately to communicate their meaning clearly with focus on the use of nouns, verbs, pronouns, adjectives and some prepositions.', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('acfaa02e-e477-474f-9e5e-03dc195c2e6f', 'LA.1.WR.WC.11', 'Use singular and plural forms of nouns appropriately.', 'language-arts', '1', 'Writing', 'WR', 'Weather and Consequences', 'WC', '', 'K-2', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b34ce7ab-534a-4d36-928c-45f1baacb140', 'LA.1.WR.AI.1', 'Select pieces of writing that they think show their best work and explain the reasons for their selections.', 'language-arts', '1', 'Writing', 'WR', 'Attitudes and Interests', 'AI', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7abd536d-67f2-432d-b179-48e3c0da82eb', 'LA.1.WR.AI.2', 'Accept feedback about their writing and use the feedback to improve their writing.', 'language-arts', '1', 'Writing', 'WR', 'Attitudes and Interests', 'AI', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7493c14e-29e9-4230-9483-290a4afe2ff3', 'LA.1.WR.AI.3', 'Identify elements of their writing that need improvement, including content organization and style, using feedback from the teacher and peers.', 'language-arts', '1', 'Writing', 'WR', 'Attitudes and Interests', 'AI', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('60e33bd4-ca3a-45b8-bc32-e27cda2c4eca', 'LA.2.LS.SI.1', 'Participate in collaborative conversations with various partners about grade 2 topics and texts with peers and adults in small and larger groups.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('dd1341c9-b761-4366-8557-8b61633c9369', 'LA.2.LS.SI.2', 'Followed agreed-upon rules for discussion (e.g. gaining the floor respectfully, listening to others with care, speaking one at a time about topics and texts under discussion.)', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('22b935c7-ec1b-4ba5-8eb7-63292a50b869', 'LA.2.LS.SI.3', 'Build on others’ talk in conversations by connecting their comments to the remarks of others and giving critical responses.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a331ed73-ef95-4b5d-a4f7-2649732b5514', 'LA.2.LS.SI.5', 'Relate or describe key ideas or details from a text read aloud or information presented orally or through other media.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f1addc44-a5ff-4c02-aa2a-da56974fabd4', 'LA.2.LS.SI.6', 'Ask and answer questions about what a speaker says in order to clarify understanding, gather additional information or expand understanding of a topic or issue.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9eb7c631-6ae5-41e7-af19-babbed612576', 'LA.2.LS.SI.7', 'Tell a story or relate an experience with appropriate and relevant descriptive details, speaking audibly in coherent sentences', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('2a26e734-646b-452e-9b05-050dd2743fcd', 'LA.2.LS.SI.8', 'Produce complete sentences when appropriate to task and situation in order to provide requested detail or clarification.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('5b0e08b3-3e21-4e71-8b21-4e6305ed41aa', 'LA.2.LS.SI.9', 'Demonstrate the ability to stay on a selected topic when making oral presentations.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('59418e81-a644-4ebe-9bf8-19c79a40365c', 'LA.2.LS.SI.10', 'Ask for and give directions', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('25b06c94-444e-4cc7-96bd-8fe24bcb12cb', 'LA.2.LS.SI.11', 'Listen to detect a speaker’s emotional tone.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('bb9c9474-6651-442f-ace9-3de0fed64c39', 'LA.2.LS.SI.12', 'Uses appropriate volume, pitch, tone, rate and enunciation.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 12, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('cd6eee60-c8be-47d1-bfe5-04e46bc99471', 'LA.2.LS.SI.13', 'Role play sections of a story.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 13, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ae70ee88-1a0c-4d51-bb69-7529328d2016', 'LA.2.LS.SI.14', 'Recite favourite poems.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 14, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('6e780e64-27a0-4f40-a1f1-3068b188fdd6', 'LA.2.LS.SI.15', 'Listen to get the substance of a message.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 15, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d2ea802f-f9c7-4bc9-a454-6cb463250a3c', 'LA.2.LS.SI.16', 'Listen to draw correct conclusions from spoken messages.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 16, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9112bfe5-ca92-468c-b861-00224818b16d', 'LA.2.LS.SI.17', 'Use correct strategies for beginning and ending conversations.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 17, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c1126ddc-ce19-48a4-8872-1b9afee8279b', 'LA.2.LS.SI.18', 'Use gestures, facial expressions and maintain eye contact in conversations', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 18, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f2002333-1b52-41a7-84d4-16a2d703e68e', 'LA.2.LS.SI.19', 'Use turn-taking and other conventions correctly when involved in discussions.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 19, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('2348941c-8421-43da-89a1-65c3d1b9e530', 'LA.2.LS.SI.20', 'Suggest solutions for problems in classroom, stories or real-life situations.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 20, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('bd00c3de-4f22-4950-a43c-46fd3f51b0f3', 'LA.2.LS.SI.21', 'Share ideas relevant to class activities and discussions (e.g. structured A/B partners, informal partner talk.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 21, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('27afd826-3a9c-44c1-b81e-fb7d6fbfda4e', 'LA.2.LS.SI.22', 'Use language to discuss steps needed to negotiate and complete tasks in partner and group activities.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', '', 'K-2', 22, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('86ac769a-6ad9-4361-914c-832e3b287b97', 'LA.2.LS.GI.1', 'Listen to directions and correctly perform the actions/behaviours requested.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('69d1de9f-d0d0-46fe-a598-2fb394992b9e', 'LA.2.LS.GI.2', 'Listen to ascertain the cause and effect of an event told by someone.', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c1904f62-d998-46d1-a9b7-60e6b42d9b72', 'LA.2.LS.GI.3', 'Listen to items at news time in class in order to understand and explain the gist of the news item', 'language-arts', '2', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', '', 'K-2', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
