  ('849b0204-7bf9-4235-a799-586abb218384', 'LA.3.LS.SI.4', 'Ask for assistance from peers and adults.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
