  ('6c1e1c9c-3bbb-49a0-9a38-b0d14c7dc6a2', 'LA.3.LS.SI.6', 'Participate with confidence in group and class discussion on topics of personal and social interest using appropriate conversational skills and both Standard English and native language', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '3-4', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a83c26c1-dc35-49c1-8cb2-1787bddae769', 'LA.3.LS.SI.7', 'Come to discussion prepared having read or studies required material, explicitly draw on that preparation and other information known about the topic to explore ideas under discussion.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '3-4', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('23b9a5ee-61ec-4746-85ff-77132ef24736', 'LA.3.LS.SI.8', 'Report on a topic or text, tell a story, or recount an experience with appropriate facts and relevant, descriptive details, speaking clearly at an understandable pace', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '3-4', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0147fe1f-2956-4e31-9fa4-f2879cd4e40c', 'LA.3.LS.SI.9', 'Follow agreed-upon rules for discussions.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '3-4', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('dd7aef46-a43b-4d0a-929d-602a30048cae', 'LA.3.LS.SI.10', 'Engage effectively in a range of collaborative discussions with diverse partners building on others’ ideas and expressing their own clearly.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '3-4', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('82b71dce-1129-421a-9fde-a1cdd7c2774b', 'LA.3.LS.SI.11', 'Ask questions to check understanding of information presented, stay on topic and link their comments to remarks of others.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '3-4', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('79ce9c12-a972-425b-a2c9-4400a4ad2ce0', 'LA.3.LS.SI.12', 'Speak in complete sentences when appropriate to task and situation in order to provide requested detail or clarification. (allow students to use both Standard English and native language)', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '3-4', 12, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('bf16722f-e81a-4cd5-b32b-026ea27fb5fc', 'LA.3.LS.SI.13', 'Read prose and poetry aloud with fluency, rhythm, and pace, using appropriate intonation and vocal patterns to emphasize important passages of the text being read.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '3-4', 13, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('6e45b53e-7dfa-4f69-90bd-ef69212333a9', 'LA.3.LS.LC.1', 'Explain their own ideas and understanding in light of the discussion. Share ideas relevant to class activities and discussions', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('df6e929d-7357-4b6a-ace2-09e55204bd9d', 'LA.3.LS.LC.2', 'Ask and answer questions about information from a speaker, offering appropriate elaboration and detail.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c0702cfb-6895-4b86-afd1-732b5aa2d853', 'LA.3.LS.LC.3', 'Listen to determine the purpose of a speaker’s message.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7d0d4fd6-9820-46d1-86ea-ebd03f4f339f', 'LA.3.LS.LC.4', 'Organize ideas chronologically or around major points of information.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('45721efc-96f1-4cb7-a83f-4eac76a76c16', 'LA.3.LS.LC.5', 'Provide a beginning, middle and end, including concrete details that develop a central idea.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('213f655c-5766-4950-987a-01e78b5c0069', 'LA.3.LS.LC.6', 'Listen to follow simple instructions given orally on how to make or do something', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('35fe1205-53e8-49a4-ab86-7862daa286e7', 'LA.3.LS.LC.7', 'Give instructions to explain how to perform a task', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4fb75cb7-31b3-40a9-bc00-227586f582bd', 'LA.3.LS.LC.8', 'Listen to follow the sequence of events in a report given by a speaker.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1a755cb0-9fd0-41e8-9bd9-bc91cb7644bf', 'LA.3.LS.LC.9', 'Listen to express a personal response to poems, stories and other types of literary material', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('37161191-d259-4f9b-9b6d-f38701a204d2', 'LA.3.LS.LC.10', 'Discuss different possible solutions to problems', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d3dbdd49-1d15-45c0-a1c6-7309954a9d2a', 'LA.3.LS.LC.11', 'Learn to use the basic key questions – why? how? when? What/ what if?', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f9ad1c69-2c05-4339-982e-647864b192ca', 'LA.3.LS.LC.12', 'Make presentations to the class about his/her own particular interests.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 12, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0109db8d-0317-42e0-8736-7a15bc522390', 'LA.3.LS.LC.13', 'Argue a point of view and try to persuade others to support it. (allow students to use both Standard English and Creole)', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 13, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9cb014fa-0045-4158-a054-9b1257db24aa', 'LA.3.LS.LC.14', 'Create and tell stories to class/group and retell them after questioning, comparing versions.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 14, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('68b9f95a-5909-4584-8ce7-199c44921507', 'LA.3.LS.LC.15', 'Discuss concerns that directly affect his/her life in and out of school and in other areas of the curriculum.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 15, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('38c98606-2d12-492d-ad7d-4ec95d860427', 'LA.3.LS.LC.16', 'Ask and answer questions to demonstrate understanding of a topic of discussion.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 16, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d8b44fd4-347e-4e13-9bad-6deae65219f9', 'LA.3.LS.LC.17', 'Determine the main ideas and supporting details of a text read aloud or information presented in diverse media and formats including visually and orally.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 17, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
