  ('4e0ad615-b3dd-47d2-a9da-947adc95a910', 'LA.3.LS.LC.20', 'Retell, rephrase and explain what has been said by a speaker', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 20, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ea13aebd-cdfc-4b94-beca-9c496bbe2f4a', 'LA.3.LS.LC.21', 'Describe the essence of the author’s message', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 21, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('eac876ce-c7fc-4d4e-8d07-765b4a7e6963', 'LA.3.LS.LC.22', 'Listen to short excerpt to summarize the information presented', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 22, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
