  ('ca432250-d0c5-47fc-a86c-1b1b7bf93791', 'LA.3.LS.LC.24', 'Listen to differentiate between opinions expressed by a speaker and facts that can be verified', 'language-arts', '3', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '3-4', 24, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('204c86ab-ccbc-4fb0-987a-1ffb3eca4793', 'LA.3.LS.VB.1', 'Listen to identify word contractions used by a speaker', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Vocabulary Building', 'VB', NULL, '3-4', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('2e057f68-8284-4fb5-bab4-5b2625e52198', 'LA.3.LS.VB.2', 'Listen to determine word meanings from the perspectives of their use in an oral presentation.', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Vocabulary Building', 'VB', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
