  ('f6c475e2-0f5e-4cfa-9a7d-0eaaaf45dc5a', 'LA.3.LS.VB.4', 'Use words for their exact and abstract and connotative meaning in oral presentations', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Vocabulary Building', 'VB', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
