  ('3db23ee5-0b3b-44f2-a568-56f75f9ec467', 'LA.3.LS.AI.3', 'Show willingness to begin and continue conversation for school- related tasks', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Attitudes and Interests', 'AI', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b2507c87-a2dc-45a1-82f6-071c2f155268', 'LA.3.LS.AI.4', 'Show respect for the ideas of others', 'language-arts', '3', 'Listening and Speaking', 'LS', 'Attitudes and Interests', 'AI', NULL, '3-4', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
