  ('99fe8ed3-6986-4639-a17d-a81166522488', 'LA.4.R.RC.3', 'Practice strategies of making connections, predictions and inferences with an emphasis on interpretation.', 'language-arts', '4', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '3-4', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
