  ('6057a394-dfb8-4cbc-82d5-14c67c77bfe9', 'LA.4.R.RC.7', 'Determine main idea in a text and explain how it is supported by details.', 'language-arts', '4', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '3-4', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f58b99c0-9988-4267-9e56-aa1cd39acd04', 'LA.4.R.RC.8', 'Determine main idea of a passage and explain how it is supported by key details.', 'language-arts', '4', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '3-4', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
