  ('92a5feab-e860-41ec-bf92-a91817d5c3e6', 'LA.4.R.UT.6', 'Keep portfolios which will contain samples of work done, information on books and/or authors read and any other criteria set by teacher.', 'language-arts', '4', 'Reading and Viewing', 'R', 'Use of Technology', 'UT', NULL, '3-4', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
