  ('7088b2e5-4b81-4237-910c-bbc10aa6146d', 'LA.4.R.VB.2', 'Use text to determine meaning of a word or phrase', 'language-arts', '4', 'Reading and Viewing', 'R', 'Vocabulary Building', 'VB', NULL, '3-4', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
