  ('14010012-6e1a-4530-a836-50df2a437ad0', 'LA.5.WR.PA.2', 'With guidance and support from teachers, use technology to produce and publish writing (using keyboarding skills) as well as to interact and collaborate with others.', 'language-arts', '5', 'Writing', 'WR', 'Phonological Awareness', 'PA', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e423acf9-9f0f-4a34-8dc1-b996f5916c96', 'LA.5.WR.PA.3', 'Conduct short research projects that build knowledge about a topic.', 'language-arts', '5', 'Writing', 'WR', 'Phonological Awareness', 'PA', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('da0e63ac-7737-4cbb-8b65-481f104487b5', 'LA.5.WR.PA.4', 'Prepare a portfolio which shows development of language skills acquired over the year. Should contain examples of varying pieces of writings.', 'language-arts', '5', 'Writing', 'WR', 'Phonological Awareness', 'PA', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f06966ad-1095-48a9-8289-92e1ea07956c', 'LA.5.WR.PS.1', 'Provide logically ordered reasons that are supported by facts and details.', 'language-arts', '5', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('24cecdb0-979c-4fb9-a7bc-8b9ccf9d97fc', 'LA.5.WR.PS.2', 'Link opinion and reasons using words and phrases (e.g., consequently, specifically).', 'language-arts', '5', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('af341114-6810-41a0-bb08-5b7082a8aff5', 'LA.5.WR.PS.3', 'Provide a conclusion related to opinion presented.', 'language-arts', '5', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('362467ee-c697-40b8-b731-40d53b182218', 'LA.5.WR.PS.4', 'Produce clear and coherent writing in which the development and organization are appropriate to task, purpose, and audience.', 'language-arts', '5', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4933b52d-ff25-45f7-ad15-fd845d9a484a', 'LA.5.WR.PS.5', 'With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising, and editing.', 'language-arts', '5', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('39eef44a-3fe2-4862-a093-2b4d3ce3d41c', 'LA.5.WR.PS.6', 'Self-monitor use of writing process and writing strategies.', 'language-arts', '5', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('26fecb63-c09c-4c77-b702-2284ddf53aeb', 'LA.5.WR.GM.1', 'Demonstrate command of the conventions of standard English grammar and usage when writing.', 'language-arts', '5', 'Writing', 'WR', 'Grammar and Mechanics', 'GM', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('e62d5a05-d3b4-43e1-910d-2fd967fdd896', 'LA.5.WR.GM.2', 'Demonstrate command of the conventions of standard English capitalization, punctuation, and spelling when writing.', 'language-arts', '5', 'Writing', 'WR', 'Grammar and Mechanics', 'GM', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b3f95238-7179-49ae-90bf-500a6d69243e', 'LA.5.WR.GM.3', 'Use context (e.g., definitions, examples, or restatements in text) as a clue to the meaning of a word or phrase.', 'language-arts', '5', 'Writing', 'WR', 'Grammar and Mechanics', 'GM', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('dba2c36d-432d-400d-aeef-374a031f8ee9', 'LA.5.WR.GM.4', 'Consult reference materials (e.g., dictionaries, glossaries, thesauruses), both print and digital, to find the pronunciation and determine or clarify the precise meaning of key words and phrases.', 'language-arts', '5', 'Writing', 'WR', 'Grammar and Mechanics', 'GM', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('976bc826-9a19-44bb-b22b-ac264ea0789c', 'LA.5.WR.GM.5', 'Explain the meaning of figurative language encountered in texts', 'language-arts', '5', 'Writing', 'WR', 'Grammar and Mechanics', 'GM', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('772aaa36-b5c5-44d9-aa3f-b1c1769b3a30', 'LA.5.WR.GM.6', 'Use the relationship between particular words (e.g., synonyms, antonyms, homographs) to better understand each of the words.', 'language-arts', '5', 'Writing', 'WR', 'Grammar and Mechanics', 'GM', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('44c1fc2d-f109-46c1-b352-6b88c38e3ed4', 'LA.5.WR.GM.7', 'Ensure subject-verb and pronoun-antecedent agreement.', 'language-arts', '5', 'Writing', 'WR', 'Grammar and Mechanics', 'GM', NULL, '5-6', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('94901687-551d-4655-b55b-56ace6c3377e', 'LA.5.WR.GM.8', 'Correctly use frequently confused words (e.g., to/too/two; there/their/they’re).', 'language-arts', '5', 'Writing', 'WR', 'Grammar and Mechanics', 'GM', NULL, '5-6', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('029d06ff-ed1b-4e1f-b2a5-c01e227d4aff', 'LA.6.LS.LC.1', 'Report on a topic or text or present an opinion, sequencing ideas logically and using appropriate facts and relevant, descriptive details to support main ideas or themes; speak clearly at an understandable pace.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('db4c3408-8f0d-42e6-9b65-2b8861d9ca3d', 'LA.6.LS.LC.2', 'Apply knowledge of language to understand how language functions in different contexts, to make effective choices for meaning or style, and to comprehend more fully when listening.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1bc71e30-4783-480c-b58b-ad05c0029ae4', 'LA.6.LS.LC.3', 'Present information, findings, and supporting evidence such that listeners can follow the line of reasoning and the organization, development, and style are appropriate to task, purpose, and audience.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a67a14c6-d789-4bd6-b294-f9796e8c550e', 'LA.6.LS.LC.4', 'Synthesize viewpoints of others and discuss options to resolve any outstanding differences', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7117be9b-2ebe-4ccc-8cea-eda4dab9db19', 'LA.6.LS.LC.5', 'Listen to oral presentations to identify useful details for application', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LC', 'LC', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('7c4f84d3-f837-4c43-aa40-29dcdd79c6fb', 'LA.6.LS.LE.1', 'Listen to speeches, songs, poems etc. to determine preferences', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LE', 'LE', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c20c35f0-2093-4292-a25c-7fd228ac3c8e', 'LA.6.LS.LE.2', 'Listen to traditional stories and songs to learn about culture', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LE', 'LE', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8acefc3f-12d1-45d1-9009-8046d47e2727', 'LA.6.LS.LE.3', 'Listen to audio material to expand cultural perspectives/ identify differences among cultures and sub-cultures', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LE', 'LE', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d2e63fd0-6e03-4b77-9cac-7390006b238a', 'LA.6.LS.GI.1', 'Use precise language and domain-specific vocabulary to inform about or explain the topic', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('14c62972-3de7-4368-b220-4eaa836bd38f', 'LA.6.LS.GI.2', 'Present information, findings, and supporting evidence clearly, concisely, and logically such that listeners can follow the line of reasoning and the organization, development, substance, and style are appropriate to purpose, audience, and task.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('edf5996f-5f6d-43d8-9972-1f4b376e2136', 'LA.6.LS.GI.3', 'Present/discuss in their own words, information that is accurate, states a topic, follows an organizational structure and includes specific and relevant examples and details (e.g. results of a scientific experiment, historical or recreational event)', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0e28dd50-85c2-4b1d-9b5e-2490b2e678d2', 'LA.6.LS.GI.4', 'Formulate and ask questions for clarification (that require background or contextual information)', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('05be27bb-dcda-4552-ae73-5efa90967823', 'LA.6.LS.GI.5', 'Identify parts of oral/audio presentations which contain required details/information', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Group Identity', 'GI', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1f46c992-a236-4ef9-984a-9a41d0b1fe06', 'LA.6.LS.SI.1', 'Adapt speech to a variety of contexts and tasks, using formal English and native language when appropriate to task and situation', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('32316b1f-becc-4dc6-b31f-8076b21264e6', 'LA.6.LS.SI.2', 'Recognize variations from standard English in their own and others’ speaking, and identify and use strategies to improve expression in conventional language', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('81b46273-fcf1-4e97-aca9-22ffb0a71d23', 'LA.6.LS.SI.3', 'Demonstrate attentive listening in non-verbal ways (e.g. take notes, sketch or diagram key ideas, nod to show agreement, use facial expressions)', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f8e7a812-42d8-46d9-80fb-f6a9cbfd236e', 'LA.6.LS.SI.4', 'Use vocabulary appropriate to topic and audience (e.g. content specific words such as ‘global warming’)', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('73cd41f8-f1f3-40d6-b040-05add62d5ad5', 'LA.6.LS.SI.5', 'Use appropriate strategies for making connections with audience (e.g. position themselves so others can see and hear, use body language such as smiling or making eye contact)', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Social Interaction', 'SI', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('70379397-90ca-42d1-8995-291fdf24d2f8', 'LA.6.LS.LR.1', 'Demonstrate command of the conventions of standard English grammar and usage when speaking.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LR', 'LR', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b5c2f3e3-094a-4a03-8bf2-c6b4ae6afd2a', 'LA.6.LS.LR.2', 'Include multimedia components (e.g., graphics, sound) and visual displays in presentations when appropriate to enhance the development of main ideas or themes.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LR', 'LR', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('4cce8820-5d32-430c-b98f-4bfa25f7fd78', 'LA.6.LS.LR.3', 'Explain their own viewpoints and give reasons and if applicable, support judgments through references to a text and prior knowledge and other sources of evidence.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LR', 'LR', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('463aabf8-d429-4dbe-bb52-5a748eb03e02', 'LA.6.LS.LR.4', 'Identify, in conversation with teacher and peers, those strategies they found most helpful before, during and after listening and speaking and what steps they can take to improve their oral communication skills.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'LR', 'LR', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('81a02c46-3f3a-48ab-998a-2bdde3d6546e', 'LA.6.LS.EI.1', 'Integrate and evaluate information presented in diverse media and formats, including visually and orally.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Evaluating Ideas', 'EI', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('178ef61e-f4d5-4958-a35a-6a2c3a0555d8', 'LA.6.LS.EI.2', 'Evaluate a speaker’s point of view, reasoning, and use of evidence', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Evaluating Ideas', 'EI', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('d75dfee6-f4d7-4ce3-9026-f160f6fd92e1', 'LA.6.LS.EI.3', 'Adapt speech to a variety of contexts and communicative tasks, demonstrating command of formal English when indicated or appropriate.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Evaluating Ideas', 'EI', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f99f7b7a-e564-4354-9224-e9d257d9ab9d', 'LA.6.LS.EI.4', 'Use knowledge of language and its conventions when speaking or listening', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Evaluating Ideas', 'EI', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('12bae88b-aac7-4423-98b7-2d5c61951496', 'LA.6.LS.EI.5', 'Apply knowledge of language to understand how language functions in different context to make effective choices for meaning or style, and to comprehend more fully when listening.', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Evaluating Ideas', 'EI', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8f6a9f7f-d434-4e98-9152-0ed0c30d5809', 'LA.6.LS.EI.6', 'Identify persuasive and propaganda techniques used in television and identify false and misleading information', 'language-arts', '6', 'Listening and Speaking', 'LS', 'Evaluating Ideas', 'EI', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('cf603385-8420-4767-8b4f-3e899856f727', 'LA.6.R.RC.1', 'Recognize the implication of words, phrases used in the passage', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8990177c-12e4-4256-bbdc-96aa6f28233c', 'LA.6.R.RC.2', 'Draw logical conclusions from information given', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('974c662c-e107-47ab-a638-82ddc93c8762', 'LA.6.R.RC.3', 'Substantiate from the passage opinions held', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('ad2014bd-6796-46ad-8c9c-9145645731e5', 'LA.6.R.RC.4', 'Make inferences from the passage', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8a984c63-3d19-42c4-b32c-19de138699c6', 'LA.6.R.RC.5', 'Determine the author’s point of view in a selected passage', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('48975709-0e2b-495a-810c-f9b6016ddd29', 'LA.6.R.RC.6', 'Summarise main points of passage and use textual evidence to make logical predictions and insightful inferences.', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1de3e362-90ff-4464-aadf-e818fe7b8042', 'LA.6.R.RC.7', 'Identify main ideas and synthesise multiple ideas to arrive at original thinking.', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b66a4a48-26b2-4707-9a61-88e9920e459d', 'LA.6.R.RC.8', 'Describe the author’s theme/purpose and cite supporting evidence.', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('ea2cdde6-afdf-45f5-af8d-a0c5e741f378', 'LA.6.R.RC.9', 'Read orally with accuracy, appropriate rate and expression on successive occasions.', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b5e0e0e4-d047-46a9-8726-3f8c14520634', 'LA.6.R.RC.10', 'Use a workshop model pupils listen to a read aloud story that demonstrates comprehension strategies that they then apply to their independent reading', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('25d1b196-9c34-4aa4-b35c-6138eef7b439', 'LA.6.R.RC.11', 'Connect and clarify main ideas by identifying their relationship to other sources and related topics.', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('1515bda4-9716-4c27-b370-2cafcfd4a1e1', 'LA.6.R.RC.12', 'Clarifying and understanding of texts by creating outlines, logical notes, summaries, reports and graphic representations (graphs, word clouds, word splash)', 'language-arts', '6', 'Reading and Viewing', 'R', 'Resources in the Community', 'RC', NULL, '5-6', 12, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
