  ('442625b6-17a8-466c-a0e0-3b3da21e8979', 'LA.6.R.AI.4', 'Give reasons for their choice of particular texts', 'language-arts', '6', 'Reading and Viewing', 'R', 'Attitudes and Interests', 'AI', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
