  ('2e219ec7-7302-4459-bd31-1627fe1c1c5d', 'LA.6.R.VL.4', 'create/integrate text/presentation to tell a story or explain a concept', 'language-arts', '6', 'Reading and Viewing', 'R', 'Visual Literacy', 'VL', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('10ecc2ad-9ae6-43b0-bc87-34893b534d0a', 'LA.6.WR.PS.1', 'Produce clear and coherent writing in which the development, organization, and style are appropriate to task, purpose, and audience.', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('efad8589-1dae-47c7-9008-81a1ee452041', 'LA.6.WR.PS.2', 'Link opinion and reasons using words, phrases, and clauses, (e.g., consequently, specifically)', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('87f086de-da7a-4697-b998-bff6b5a53290', 'LA.6.WR.PS.3', 'Introduce a topic clearly, state an opinion, and create an organizational structure in which ideas are logically grouped to support the writer’s purpose.', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('dfd10d8d-1501-45b8-98c5-89ef8a93130e', 'LA.6.WR.PS.4', 'Link ideas within and across categories of information using words, phrases, and clauses (e.g., in contrast, especially).', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 4, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('a4a746af-ed3d-4262-b96d-9f2957a8b23d', 'LA.6.WR.PS.5', 'Use a variety of transitional words, phrases, and clauses to manage the sequence of events.', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('64944aa9-98ea-4d76-8c2d-feb59fef655c', 'LA.6.WR.PS.6', 'Use concrete words and phrases and sensory details to convey experiences and events precisely', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 6, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('c5ff1848-3552-4b4d-9853-c4918240cae2', 'LA.6.WR.PS.7', 'Produce clear and coherent writing in which the development and organization are appropriate to task, purpose, and audience.', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 7, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00');
INSERT INTO curriculum_learning_standards (id, code, description, subject, grade_level, strand, strand_code, sub_strand, sub_strand_code, domain, grade_grouping, standard_number, created_at, updated_at) VALUES
  ('c7aed622-eb09-492b-a36d-927976e19d70', 'LA.6.WR.PS.8', 'Maintain consistency in style and tone.', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 8, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9a0ba81d-0bbe-474e-b1ce-4826db0a28e5', 'LA.6.WR.PS.9', 'Choose language that expresses ideas precisely and concisely, recognising and eliminating wordiness and redundancy.', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 9, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('f8d3c381-3d92-4bb0-8cd0-0dc4bb696b8b', 'LA.6.WR.PS.10', 'Produce clear and coherent writing in which the development, organization, and style are appropriate to task, purpose, and audience.', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 10, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('9f4eed1b-475a-4bb2-ad82-2768a7005a3f', 'LA.6.WR.PS.11', 'Use narrative techniques, such as dialogue and description, to develop experiences and events.', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 11, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('fcd7165c-064e-46e1-b4da-8a1168098361', 'LA.6.WR.PS.12', 'Use a variety of transition words, phrases, and clauses to convey sequence and signal shifts from one time frame or setting to another.', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 12, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('0a70c462-f3da-4eb8-a7f1-83428428d3bb', 'LA.6.WR.PS.13', 'Demonstrate independent use of writing process to create test', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 13, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('8a40b631-54bf-4048-856f-b14ea631bf3b', 'LA.6.WR.PS.14', 'Include multimedia components and visual displays in presentations to clarify and emphasise salient points', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 14, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('534515e1-481f-4d60-a19a-13a14a728569', 'LA.6.WR.PS.15', 'Make strategic use of digital media (e.g. textual, graphical, audio, visual and interactive elements) in presentations to enhance understanding of findings, reasoning and evidence and to add interest', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 15, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('2e7034db-6892-4097-a802-e942007b55f3', 'LA.6.WR.PS.16', 'Make strategic use of digital media and visual displays of data to express information and enhance understanding of presentations.', 'language-arts', '6', 'Writing', 'WR', 'Physical Science', 'PS', NULL, '5-6', 16, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('877d4ce3-3fb8-4233-be4e-c986e0ed05d0', 'LA.6.WR.PA.1', 'Write narratives to develop real or imagined experiences or events using effective technique, well-chosen details, and well-structured event sequences.', 'language-arts', '6', 'Writing', 'WR', 'Phonological Awareness', 'PA', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('744074f1-85b3-49fc-80a0-3181b141048f', 'LA.6.WR.PA.2', 'With guidance and support from peers and adults, develop and strengthen writing as needed by planning, revising, editing, rewriting, or trying a new approach.', 'language-arts', '6', 'Writing', 'WR', 'Phonological Awareness', 'PA', NULL, '5-6', 2, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('72d46558-6644-4515-9831-ed2d6b7c44c6', 'LA.6.WR.PA.3', 'With some guidance and support from adults, use technology, including the Internet, to produce and publish writing as well as to interact and collaborate with others.', 'language-arts', '6', 'Writing', 'WR', 'Phonological Awareness', 'PA', NULL, '5-6', 3, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
