  ('f96d2cf4-6a54-4ffd-94cc-50f4b3cf7c02', 'LA.6.WR.PA.5', 'Create texts, including graphics to explain a concept in simple non-technical terms', 'language-arts', '6', 'Writing', 'WR', 'Phonological Awareness', 'PA', NULL, '5-6', 5, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
  ('b2f371d3-a69d-421c-8a51-068f2f94d50e', 'LA.6.WR.GM.1', 'Demonstrate command of the conventions of standard English grammar and usage when writing.', 'language-arts', '6', 'Writing', 'WR', 'Grammar and Mechanics', 'GM', NULL, '5-6', 1, '2026-01-03T13:23:37.075008+00:00', '2026-01-03T13:23:37.075008+00:00'),
